// ══════════════════════ DISPLAY DIMS ══════════════════════
// Long parts: N-S orientation — stored PARALLEL to the corridor
//   dW = fp × W    (narrow E-W footprint = bundles side-by-side)
//   dH = L         (tall N-S = full beam length going north)
//   Access: forklift enters the zone from the SOUTH end, drives north to the beam's south face
//   The central 8-10m corridor provides the highway; forklift turns E→zone at the staging area
//
// Box items: compact near-square grid, rotation allowed by AI
function getDD(it){
  const{L,W,H,is_long,rotated,bundles,stack}=it;
  // Forklift 5T max lift 4m — caps stack height
  const maxByFork = Math.max(1, Math.floor(FORK_MAX_H / H));
  const effStack = Math.min(stack, maxByFork);
  const fp = Math.ceil(bundles / effStack);
  // E-W row with grid wrap: fit within smaller zone limit
  const zoneW = Math.min(maxZoneWL, maxZoneWR);
  const maxCols = Math.max(1, Math.floor(zoneW / W));
  const cols = Math.min(fp, maxCols);
  const rows = Math.ceil(fp / cols);
  const dW = cols * W;
  const dH = rows * L;
  return{dW,dH,fp,effStack,cols,rows};
}
function stackH(it){return it.H*Math.min(it.stack,Math.ceil(it.bundles/it.floor_pos));}

// Short display name (remove long Chinese / parenthetical suffixes)
function shortName(name){
  let s=name.replace(/[（(][^)）]*[)）]/g,'').replace(/区$/,'').trim();
  return s.length>14 ? s.slice(0,13)+'…' : s;
}

// ══════════════════════ PACKING ══════════════════════
// Pack items into E-W lane-columns on one side of the corridor.
// side='left' : items extend WESTWARD  (local x ≤ 0, right-edge=0=corridor)
// side='right': items extend EASTWARD  (local x ≥ 0, left-edge=0=corridor)
// - Tries rotation for BOX items to minimise N-S waste in lane
// - Returns {placed, depth, height, laneData, rotMap}

function packSide(sideItems, side){
  if(!sideItems.length) return{placed:{},depth:0,height:0,laneData:[]};
  const zoneLimit = side==='left' ? maxZoneWL : maxZoneWR;

  // Try different sort orders
  const sorts=[
    // By volume descending
    [...sideItems].sort((a,b)=>(b.bundles*b.L*b.W)-(a.bundles*a.L*a.W)),
    // By N-S extent (dH) descending — standard NFDH
    [...sideItems].sort((a,b)=>{const{dH:ah}=getDD(a);const{dH:bh}=getDD(b);return bh-ah;}),
    // By E-W width (dW) descending
    [...sideItems].sort((a,b)=>{const{dW:aw}=getDD(a);const{dW:bw}=getDD(b);return bw-aw;}),
    // By area descending
    [...sideItems].sort((a,b)=>areaOf(b)-areaOf(a)),
  ];

  let best=null, bestArea=Infinity;
  for(const sorted of sorts){
    const r=tryPack(sorted, 0, side);
    if(r.depth<=zoneLimit){
      const area=r.depth*r.height;
      if(area<bestArea){bestArea=area;best=r;}
    }
  }

  // Fallback: if nothing fit within zone limit, pick smallest depth
  if(!best){
    let bestDepth=Infinity;
    for(const sorted of sorts){
      const r=tryPack(sorted, 0, side);
      if(r.depth<bestDepth){bestDepth=r.depth;best=r;}
    }
  }

  if(!best) best={placed:{},depth:0,height:0,laneData:[]};
  if(best&&best.rotMap){
    for(const it of sideItems){
      if(best.rotMap[it.id]!==undefined) it.rotated=best.rotMap[it.id];
    }
  }
  return best;
}

function tryPack(sorted, targetH, side){
  // SHELF-BASED PACKING (NFDH - Next Fit Decreasing Height)
  // Multiple part codes pack side-by-side on same shelf until zone width full
  // Then start new shelf. Produces compact, tight layout.
  const rotMap={};
  const zoneLimit = side==='left' ? maxZoneWL : maxZoneWR;

  // Build blocks: one block per part code
  // Each block has: code, items[], totalW (E-W footprint), maxH (N-S extent)
  const blockMap={};
  const blockOrder=[];
  for(const it of sorted){
    const code=it.item||it.id;
    if(!blockMap[code]){blockMap[code]={items:[],code,totalW:0,maxH:0};blockOrder.push(code);}
    const{dW,dH}=getDD(it);
    rotMap[it.id]=false;
    blockMap[code].items.push({it,dW,dH,localX:blockMap[code].totalW});
    blockMap[code].totalW+=dW+GAP;
    blockMap[code].maxH=Math.max(blockMap[code].maxH,dH);
  }
  // Fix trailing GAP
  for(const code of blockOrder){
    if(blockMap[code].items.length>0) blockMap[code].totalW-=GAP;
  }

  // Create blocks array sorted by maxH descending (tallest first for NFDH)
  const blocks=blockOrder.map(c=>blockMap[c]);
  blocks.sort((a,b)=>b.maxH-a.maxH);

  // If any single block exceeds zone limit, split it into sub-blocks
  const finalBlocks=[];
  for(const blk of blocks){
    if(blk.totalW<=zoneLimit){
      finalBlocks.push(blk);
    } else {
      // Split block into sub-rows that fit within zone limit
      let curW=0, curItems=[], curMaxH=0;
      for(const entry of blk.items){
        if(curItems.length>0 && curW+GAP+entry.dW>zoneLimit){
          finalBlocks.push({code:blk.code,items:curItems.map((e,i)=>{
            let x=0;for(let j=0;j<i;j++)x+=curItems[j].dW+GAP;
            return{...e,localX:x};
          }),totalW:curW,maxH:curMaxH});
          curW=0; curItems=[]; curMaxH=0;
        }
        curItems.push(entry);
        curW+=(curItems.length>1?GAP:0)+entry.dW;
        curMaxH=Math.max(curMaxH,entry.dH);
      }
      if(curItems.length>0){
        finalBlocks.push({code:blk.code,items:curItems.map((e,i)=>{
          let x=0;for(let j=0;j<i;j++)x+=curItems[j].dW+GAP;
          return{...e,localX:x};
        }),totalW:curW,maxH:curMaxH});
      }
    }
  }

  // SHELF PACKING (NFDH - Next Fit Decreasing Height)
  // Each shelf: {y, height, usedW, blocks[]}
  const shelves=[];

  for(const blk of finalBlocks){
    // Try to fit on existing shelf (first fit)
    let placed=false;
    for(const shelf of shelves){
      if(shelf.usedW + GAP + blk.totalW <= zoneLimit){
        // Fits! Add to this shelf
        blk.shelfX = shelf.usedW + GAP;
        blk.shelfY = shelf.y;
        shelf.usedW += GAP + blk.totalW;
        shelf.height = Math.max(shelf.height, blk.maxH);
        shelf.blocks.push(blk);
        placed=true;
        break;
      }
    }
    if(!placed){
      // New shelf
      const shelfY = shelves.length===0 ? 0 :
        shelves[shelves.length-1].y + shelves[shelves.length-1].height + LANE_G;
      blk.shelfX = 0;
      blk.shelfY = shelfY;
      shelves.push({y:shelfY, height:blk.maxH, usedW:blk.totalW, blocks:[blk]});
    }
  }

  // Position items
  const placed={};
  const laneData=[];
  let maxDepth=0;

  for(const shelf of shelves){
    const y = TOP_M + shelf.y;
    // Record lane data for each block in shelf
    for(const blk of shelf.blocks){
      const blockX = blk.shelfX;
      if(side==='left'){
        // Left side: x goes negative from corridor
        const maxW = shelf.usedW;
        laneData.push({x:-maxW+blockX, maxDW:blk.totalW, height:blk.maxH, code:blk.code, isRow:true, y:y});
        for(const entry of blk.items){
          placed[entry.it.id]={x:-maxW+blockX+entry.localX, y, rot:false};
        }
      } else {
        laneData.push({x:blockX, maxDW:blk.totalW, height:blk.maxH, code:blk.code, isRow:true, y:y});
        for(const entry of blk.items){
          placed[entry.it.id]={x:blockX+entry.localX, y, rot:false};
        }
      }
    }
    maxDepth=Math.max(maxDepth, shelf.usedW);
  }

  const totalHeight = shelves.length>0 ?
    shelves[shelves.length-1].y + shelves[shelves.length-1].height + GAP : 0;

  return{placed,depth:maxDepth,height:totalHeight,laneData,rotMap};
}

