// ══════════════════════ STRATEGIES ══════════════════════
let curStrat='typeSplit';
const STRAT_DESC={
  typeSplit: 'Long parts LEFT, box items RIGHT — one category per side, no mixed handling',
  compact:   'Minimise total yard footprint — tries multiple depths, picks smallest rental area',
  fifo:      'FIFO — items from Ship 1 nearest south (first in, first accessible)',
  accessFirst: 'Quick Access — items with most bundles placed closest to corridor',
  projectCluster: 'Group by project field, each project gets one side or grouped together'
};
function onStratChange(){
  curStrat=document.getElementById('stratSel').value;
  document.getElementById('stratDesc').textContent=STRAT_DESC[curStrat]||'';
  runAI();
}

function onCorrChange(){
  const val=document.getElementById('corrSel').value;
  CORR_W=val==='wide'?8.0:3.5;
  if(layout)runAI();
}

// ── Helpers ──
// Group items by part code (same part name MUST stay on one side)
function groupByCode(arr){
  const m={};
  for(const it of arr){const k=it.item||it.id;if(!m[k])m[k]=[];m[k].push(it);}
  return Object.values(m);
}
// Greedy balance groups into L/R by some weight function
function balanceGroups(groups, weightFn){
  const lI=[],rI=[];let la=0,ra=0;
  for(const grp of groups){
    const w=grp.reduce((s,it)=>s+weightFn(it),0);
    if(la<=ra){grp.forEach(it=>lI.push(it));la+=w;}
    else{grp.forEach(it=>rI.push(it));ra+=w;}
  }
  return{lItems:lI,rItems:rI};
}
function areaOf(it){const{dW,dH}=getDD(it);return dW*dH;}

// ══════════════════════ AUTO-FIT ZOOM ══════════════════════
function autoFitZoom(){
  if(!layout)return;
  const{totalW,totalH}=layout;
  const fullH=totalH+STAGING+TRUCK_L+7;
  const padX=40, padY=40;
  const zx=(cvsW-padX)/totalW;
  const zy=(cvsH-padY)/fullH;
  zoom=Math.min(zx,zy)*0.92;
  camX=(cvsW-totalW*zoom)/2;
  camY=(cvsH-fullH*zoom)/2;
}

// ══════════════════════ RUN AI ══════════════════════
function runAI(){
  if(!items.length)return;
  // Read zone width limits from UI
  maxZoneWL=parseFloat(document.getElementById('lzW').value)||15;
  maxZoneWR=parseFloat(document.getElementById('rzW').value)||15;
  const{lItems,rItems}=getStrategyItems();
  applyLayout(lItems,rItems);
  autoFitZoom();
  draw();
}

function getStrategyItems(){
  const groups=groupByCode(items);
  // Strip mode always on: dW=W, dH=fp*L for all items
  switch(curStrat){

    case 'typeSplit':
    default: {
      // Long items LEFT, box items RIGHT — each category one side
      const lI=[], rI=[];
      for(const grp of groups){
        if(grp[0].is_long) grp.forEach(it=>lI.push(it));
        else grp.forEach(it=>rI.push(it));
      }
      return{lItems:lI, rItems:rI};
    }

    case 'compact': {
      // Try multiple zone widths within user limits, pick smallest rental area
      const savedL=maxZoneWL, savedR=maxZoneWR;
      let bestArea=Infinity, bestL=null, bestR=null, bestLW=savedL, bestRW=savedR;
      for(let mw=3;mw<=Math.max(savedL,savedR);mw+=1){
        maxZoneWL=Math.min(mw,savedL); maxZoneWR=Math.min(mw,savedR);
        // Try different balancing approaches
        const sorted=[...groups].sort((a,b)=>b.reduce((s,i)=>s+areaOf(i),0)-a.reduce((s,i)=>s+areaOf(i),0));
        const{lItems:tL,rItems:tR}=balanceGroups(sorted, areaOf);
        const lp=packSide(tL,'left'), rp=packSide(tR,'right');
        const tw=lp.depth+SIDE_M+CORR_W+rp.depth+SIDE_M;
        const th=Math.max(lp.height,rp.height)+TOP_M+SIDE_M;
        if(tw*th<bestArea){bestArea=tw*th;bestL=tL;bestR=tR;bestLW=maxZoneWL;bestRW=maxZoneWR;}
      }
      maxZoneWL=bestLW; maxZoneWR=bestRW;
      return{lItems:bestL||[], rItems:bestR||[]};
    }

    case 'fifo': {
      // FIFO — items from Ship 1 nearest south (first in, first accessible)
      // Sort groups by ship index ascending, balance L/R
      groups.sort((a,b)=>{
        const aShip=Math.min(...a.map(i=>i.si)), bShip=Math.min(...b.map(i=>i.si));
        return aShip-bShip;
      });
      return balanceGroups(groups, areaOf);
    }

    case 'accessFirst': {
      // Quick Access — items with most bundles placed closest to corridor
      groups.sort((a,b)=>{
        const aB=a.reduce((s,i)=>s+i.bundles,0), bB=b.reduce((s,i)=>s+i.bundles,0);
        return bB-aB;
      });
      return balanceGroups(groups, areaOf);
    }

    case 'projectCluster': {
      // Group by project field, each project gets one side or grouped together
      const projectMap={};
      for(const grp of groups){
        const proj=grp[0].project||'default';
        if(!projectMap[proj])projectMap[proj]=[];
        projectMap[proj].push(...grp);
      }
      const projGroups=Object.values(projectMap);
      return balanceGroups(projGroups, areaOf);
    }
  }
}



function applyLayout(lItems, rItems){
  // Standard packing for all strategies
  const lp=packSide(lItems,'left');
  const rp=packSide(rItems,'right');

  const corrL=lp.depth+SIDE_M;
  const corrR=corrL+CORR_W;
  const totalW=corrR+rp.depth+SIDE_M;
  const totalH=Math.max(lp.height,rp.height)+TOP_M+SIDE_M;
  pos={};
  for(const[id,p]of Object.entries(lp.placed)) pos[id]={x:corrL+p.x,y:p.y};
  for(const[id,p]of Object.entries(rp.placed)) pos[id]={x:corrR+p.x,y:p.y};
  const leftLanes=(lp.laneData||[]).map(l=>({x:corrL+l.x,maxDW:l.maxDW,height:l.height,code:l.code,isRow:l.isRow,y:l.y}));
  const rightLanes=(rp.laneData||[]).map(l=>({x:corrR+l.x,maxDW:l.maxDW,height:l.height,code:l.code,isRow:l.isRow,y:l.y}));
  // Build zone color map — each lane (row) gets a unique color
  zoneColorMap={};
  let zIdx=0;
  // Helper: assign items to lane by matching placed Y to lane Y
  function assignLaneColors(lanes, placed, sideItems){
    for(const lane of lanes){
      if(!lane.isRow) continue;
      const ci=zIdx%ZONE_PALETTE.length;
      for(const it of sideItems){
        const pid=it.id;
        const p=placed[pid];
        if(!p) continue;
        if(Math.abs(p.y - lane.y)<0.02 && (it.item||it.id)===lane.code){
          zoneColorMap[pid]=ci;
        }
      }
      zIdx++;
    }
  }
  assignLaneColors(lp.laneData||[], lp.placed, lItems);
  assignLaneColors(rp.laneData||[], rp.placed, rItems);
  layout={corrL,corrR,totalW,totalH,
    leftItems:new Set(lItems.map(i=>i.id)),
    rightItems:new Set(rItems.map(i=>i.id)),
    leftLanes,rightLanes,
    strategy:curStrat};
  invalidateReport();
  invalidateTruckTrips();
  updateMetrics();
  fit();
}

function resetPos(){
  items.forEach(it=>it.rotated=false);
  pos={};layout=null;
  invalidateReport();invalidateTruckTrips();
  autoFitZoom();
  draw();
}

// ══════════════════════ CANVAS ══════════════════════
const cvs=document.getElementById('cvs');
const ctx=cvs.getContext('2d');
const dpr=window.devicePixelRatio||1;
// Logical (CSS) dimensions — use these instead of cvs.width/height
let cvsW=800, cvsH=600;
function resize(){
  const p=cvs.parentElement;
  cvsW=p.clientWidth; cvsH=p.clientHeight;
  cvs.width=cvsW*dpr; cvs.height=cvsH*dpr;
  cvs.style.width=cvsW+'px'; cvs.style.height=cvsH+'px';
  ctx.setTransform(dpr,0,0,dpr,0,0);
  draw();
}
window.addEventListener('resize',resize);
setTimeout(resize,60);

function fit(){
  if(!layout){draw();return;}
  autoFitZoom();
  draw();
}
function chZ(f){
  const cx=cvsW/2,cy=cvsH/2;
  const wx=(cx-camX)/zoom,wy=(cy-camY)/zoom;
  zoom*=f;
  camX=cx-wx*zoom; camY=cy-wy*zoom;
  draw();
}

// ══════════════════════ COLOURS ══════════════════════
// Zone color palette — 20 distinct colors for different zones/lanes
const ZONE_PALETTE=[
  ['#3b82f6','#1d4ed8'], // blue
  ['#22c55e','#15803d'], // green
  ['#f59e0b','#d97706'], // amber
  ['#ef4444','#dc2626'], // red
  ['#8b5cf6','#7c3aed'], // violet
  ['#06b6d4','#0891b2'], // cyan
  ['#ec4899','#db2777'], // pink
  ['#84cc16','#65a30d'], // lime
  ['#f97316','#ea580c'], // orange
  ['#14b8a6','#0d9488'], // teal
  ['#a855f7','#9333ea'], // purple
  ['#0ea5e9','#0284c7'], // sky
  ['#10b981','#059669'], // emerald
  ['#e11d48','#be123c'], // rose
  ['#eab308','#ca8a04'], // yellow
  ['#6366f1','#4f46e5'], // indigo
  ['#d946ef','#c026d3'], // fuchsia
  ['#2dd4bf','#14b8a6'], // teal-light
  ['#fb923c','#f97316'], // orange-light
  ['#38bdf8','#0ea5e9'], // sky-light
];
window.ZONE_PALETTE = ZONE_PALETTE;
var zoneColorMap={}; // id → zone palette index
const C={
  longL:'#3b82f6',  longLd:'#1d4ed8',
  longR:'#0891b2',  longRd:'#0e7490',
  boxL :'#22c55e',  boxLd :'#15803d',
  boxR :'#84cc16',  boxRd :'#4d7c0f',
  corr :'#f0f9ff',
  stag :'#fef9c3',
  grid :'#dce0e8',
  dim  :'#dc2626',
  fklt :'#ea580c',
  truck:'#64748b'
};

// ══════════════════════ DRAW ══════════════════════
function draw(){
  ctx.clearRect(0,0,cvsW,cvsH);
  ctx.save();
  ctx.translate(camX,camY);
  ctx.scale(zoom,zoom);
  if(!layout){
    ctx.fillStyle='#94a3b8';
    ctx.font='1px Segoe UI';ctx.textAlign='center';
    ctx.fillText('Select a scenario to begin',
      cvsW/zoom/2,cvsH/zoom/2);
    ctx.restore();return;
  }
  const{corrL,corrR,totalW,totalH}=layout;
  const fullH=totalH+STAGING+TRUCK_L+7;

  // ── Paper background
  ctx.fillStyle='#ffffff';
  ctx.fillRect(0,0,totalW,fullH);

  // ── Grid
  drawGrid(totalW,fullH);

  // ── Zone tints
  ctx.fillStyle='rgba(219,234,254,0.28)';
  ctx.fillRect(0,TOP_M,corrL,totalH-TOP_M);           // left zone
  ctx.fillStyle='rgba(209,250,229,0.28)';
  ctx.fillRect(corrR,TOP_M,totalW-corrR,totalH-TOP_M); // right zone

  // ── Corridor = working zone (extends to truck)
  ctx.fillStyle=C.corr;
  ctx.fillRect(corrL,TOP_M,CORR_W,totalH-TOP_M+TRUCK_L+2);
  // Working zone hatch at south end of corridor (below storage)
  const wzTop=totalH+0.3, wzH=TRUCK_L+1.5;
  ctx.fillStyle='rgba(254,249,195,0.25)';
  ctx.fillRect(corrL,wzTop,CORR_W,wzH);
  hatch(corrL,wzTop,CORR_W,wzH,'#fde68a',1.8);

  // ── Warehouse boundary
  ctx.save();
  ctx.strokeStyle='#334155';ctx.lineWidth=0.18;ctx.setLineDash([]);
  ctx.strokeRect(SIDE_M*0.4,TOP_M*0.4,totalW-SIDE_M*0.8,totalH-TOP_M*0.4);
  ctx.restore();

  // ── Lane boundaries (dashed guides — show exact column extents)
  drawLaneBounds(layout.leftLanes, totalH, 'left', corrL);
  drawLaneBounds(layout.rightLanes,totalH, 'right',corrR);

  // ── Corridor markings
  drawCorridor(corrL,corrR,TOP_M,totalH+STAGING);

  // ── Zone south-face access arrows (forklift enters N-S long parts from S end)
  drawZoneAccess(corrL,corrR,totalW,totalH);

  // ── Forklift paths (draw BEFORE items so paths are behind)
  drawForkPaths(corrL,corrR,totalW,totalH);

  // ── Items
  for(const it of items){
    const p=pos[it.id]; if(!p)continue;
    const{dW,dH}=getDD(it);
    const onL=layout.leftItems.has(it.id);
    let fc,dc;
    if(it.id in zoneColorMap){
      const zi=zoneColorMap[it.id];
      fc=ZONE_PALETTE[zi][0];
      dc=ZONE_PALETTE[zi][1];
    } else {
      fc=it.is_long?(onL?C.longL:C.longR):(onL?C.boxL:C.boxR);
      dc=it.is_long?(onL?C.longLd:C.longRd):(onL?C.boxLd:C.boxRd);
    }
    drawItem(it,p.x,p.y,dW,dH,fc,dc,it.id===selId);
  }

  // ── Truck
  drawTruck(corrL+(CORR_W-TRUCK_W)/2, totalH+STAGING);

  // ── Annotations
  drawDims(corrL,corrR,totalW,totalH);
  drawZoneLabels(corrL,corrR,totalW,totalH);
  drawNorth(totalW-2.2,TOP_M*0.45);
  // ── Area summary box on canvas (screen-space overlay) ──
  const matA=items.reduce((s,it)=>{const{dW,dH}=getDD(it);return s+dW*dH;},0);
  const corrA=CORR_W*totalH;
  const wzA=CORR_W*(TRUCK_L+2);
  const rentA=totalW*totalH+wzA;
  const sName=document.getElementById('stratSel').selectedOptions[0].text;
  ctx.save();
  ctx.setTransform(dpr,0,0,dpr,0,0);
  // Draw in screen pixel coords (bottom-left corner)
  const sbx=12, sby=cvsH-160;
  const sbW=220, sbH=148;
  const sfs=11; // font size in px
  const spad=10; // padding
  const srow=20; // row height
  // Box background with rounded corners
  ctx.fillStyle='rgba(255,255,255,0.96)';
  ctx.strokeStyle='#cbd5e1';ctx.lineWidth=1;
  ctx.beginPath();
  ctx.moveTo(sbx+4,sby);ctx.lineTo(sbx+sbW-4,sby);ctx.quadraticCurveTo(sbx+sbW,sby,sbx+sbW,sby+4);
  ctx.lineTo(sbx+sbW,sby+sbH-4);ctx.quadraticCurveTo(sbx+sbW,sby+sbH,sbx+sbW-4,sby+sbH);
  ctx.lineTo(sbx+4,sby+sbH);ctx.quadraticCurveTo(sbx,sby+sbH,sbx,sby+sbH-4);
  ctx.lineTo(sbx,sby+4);ctx.quadraticCurveTo(sbx,sby,sbx+4,sby);
  ctx.closePath();ctx.fill();ctx.stroke();
  // Title bar
  ctx.fillStyle='#1e3a5f';
  ctx.beginPath();
  ctx.moveTo(sbx+4,sby);ctx.lineTo(sbx+sbW-4,sby);ctx.quadraticCurveTo(sbx+sbW,sby,sbx+sbW,sby+4);
  ctx.lineTo(sbx+sbW,sby+26);ctx.lineTo(sbx,sby+26);
  ctx.lineTo(sbx,sby+4);ctx.quadraticCurveTo(sbx,sby,sbx+4,sby);
  ctx.closePath();ctx.fill();
  ctx.font='bold '+sfs+'px Segoe UI';ctx.fillStyle='#fff';
  ctx.textAlign='left';ctx.textBaseline='middle';
  ctx.fillText('AREA SUMMARY',sbx+spad,sby+13);
  // Data rows
  let sry=sby+34;
  function sRow(color,label,val){
    ctx.fillStyle=color;
    ctx.beginPath();ctx.arc(sbx+spad+4,sry+srow/2-1,4,0,Math.PI*2);ctx.fill();
    ctx.font=sfs+'px Segoe UI';ctx.fillStyle='#475569';ctx.textAlign='left';ctx.textBaseline='middle';
    ctx.fillText(label,sbx+spad+14,sry+srow/2-1);
    ctx.font='bold '+sfs+'px Segoe UI';ctx.fillStyle='#1e293b';ctx.textAlign='right';
    ctx.fillText(val,sbx+sbW-spad,sry+srow/2-1);
    sry+=srow;
  }
  sRow('#22c55e','Material on ground',matA.toFixed(1)+' m\u00B2');
  sRow('#3b82f6','Corridor (drive lane)',corrA.toFixed(1)+' m\u00B2');
  sRow('#f59e0b','Working zone (truck)',wzA.toFixed(1)+' m\u00B2');
  // Separator
  ctx.strokeStyle='#e2e8f0';ctx.lineWidth=1;
  ctx.beginPath();ctx.moveTo(sbx+spad,sry);ctx.lineTo(sbx+sbW-spad,sry);ctx.stroke();
  sry+=4;
  // Rent total highlight
  ctx.fillStyle='#eff6ff';
  ctx.fillRect(sbx+4,sry,sbW-8,srow+2);
  ctx.font='bold '+(sfs+1)+'px Segoe UI';ctx.fillStyle='#1d4ed8';ctx.textAlign='left';ctx.textBaseline='middle';
  ctx.fillText('RENT TOTAL',sbx+spad,sry+srow/2+1);
  ctx.textAlign='right';
  ctx.fillText(rentA.toFixed(0)+' m\u00B2',sbx+sbW-spad,sry+srow/2+1);
  sry+=srow+6;
  // Strategy
  ctx.font='italic '+(sfs-1)+'px Segoe UI';ctx.fillStyle='#6366f1';ctx.textAlign='left';ctx.textBaseline='middle';
  ctx.fillText(sName,sbx+spad,sry+4);
  ctx.restore();

  ctx.restore();
  // Screen-space scale bar
  drawScale();

  // Alternative view modes
  if(view3d){draw3D();return;}
  if(viewFP){drawFootprintGraph();return;}
  if(viewTL){drawTruckLoad();return;}
  if(viewBD){drawBundleDetail();return;}
  if(viewRpt){drawReport();return;}
}

// ── Grid 1m / 5m ──
function drawGrid(W,H){
  ctx.setLineDash([]);
  ctx.strokeStyle=C.grid;ctx.lineWidth=0.02;
  for(let x=0;x<=Math.ceil(W)+1;x++){ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,H);ctx.stroke();}
  for(let y=0;y<=Math.ceil(H)+1;y++){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}
  ctx.strokeStyle='#c8cdd5';ctx.lineWidth=0.04;
  for(let x=0;x<=Math.ceil(W)+1;x+=5){ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,H);ctx.stroke();}
  for(let y=0;y<=Math.ceil(H)+1;y+=5){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}
}

// ── Hatch fill ──
function hatch(x,y,w,h,color,sp){
  ctx.save();ctx.beginPath();ctx.rect(x,y,w,h);ctx.clip();
  ctx.strokeStyle=color;ctx.lineWidth=0.05;ctx.setLineDash([]);
  for(let d=-h;d<w+h;d+=sp){
    ctx.beginPath();ctx.moveTo(x+d,y);ctx.lineTo(x+d+h,y+h);ctx.stroke();
  }
  ctx.restore();
}

// ── Lane boundary guides + part code labels ──
function drawLaneBounds(lanes, totalH, side, corrEdge){
  if(!lanes||!lanes.length)return;
  ctx.save();
  // Get starting zone index for this side
  const isLeft=side==='left';
  const otherLanes=isLeft?0:(layout.leftLanes||[]).filter(l=>l.isRow).length;
  let laneIdx=0;
  for(let li=0;li<lanes.length;li++){
    const lane=lanes[li];
    if(lane.isRow){
      const rx=lane.x, ry=lane.y, rw=lane.maxDW, rh=lane.height;
      const zi=(otherLanes+laneIdx)%ZONE_PALETTE.length;
      const zc=ZONE_PALETTE[zi][0];
      const zcd=ZONE_PALETTE[zi][1];

      // Solid colored border around zone
      ctx.strokeStyle=zcd;
      ctx.lineWidth=0.08;
      ctx.setLineDash([]);
      ctx.strokeRect(rx,ry,rw,rh);

      // Colored side strip (corridor-facing edge)
      ctx.fillStyle=zcd;
      const stripW=0.15;
      if(isLeft){
        ctx.fillRect(rx+rw-stripW, ry, stripW, rh);
      } else {
        ctx.fillRect(rx, ry, stripW, rh);
      }

      // Zone label with colored badge
      const fs=0.18;
      // Part code label on corridor side
      if(lane.code){
        const cfs=0.16;
        ctx.font=`700 ${cfs}px Segoe UI`;
        ctx.fillStyle=zcd;
        const shortCode=lane.code.length>14?lane.code.slice(0,13)+'…':lane.code;
        if(isLeft){
          ctx.textAlign='right';ctx.textBaseline='middle';
          ctx.fillText(shortCode,rx+rw-stripW-0.1,ry+rh/2);
        } else {
          ctx.textAlign='left';ctx.textBaseline='middle';
          ctx.fillText(shortCode,rx+stripW+0.1,ry+rh/2);
        }
      }
      // Row number badge
      ctx.font=`600 ${fs}px Segoe UI`;ctx.fillStyle='#fff';
      if(isLeft){
        ctx.textAlign='left';ctx.textBaseline='middle';
        // Badge background
        const bw=0.5, bh=0.28;
        ctx.fillStyle=zcd;
        ctx.fillRect(rx+0.05, ry+rh/2-bh/2, bw, bh);
        ctx.fillStyle='#fff';
        ctx.fillText(`Z${otherLanes+laneIdx+1}`,rx+0.1,ry+rh/2);
      } else {
        const bw=0.5, bh=0.28;
        ctx.fillStyle=zcd;
        ctx.fillRect(rx+rw-bw-0.05, ry+rh/2-bh/2, bw, bh);
        ctx.fillStyle='#fff';
        ctx.textAlign='right';ctx.textBaseline='middle';
        ctx.fillText(`Z${otherLanes+laneIdx+1}`,rx+rw-0.1,ry+rh/2);
      }
      laneIdx++;
    } else {
      // Legacy column layout
      const lx=lane.x, ly=TOP_M, lw=lane.maxDW, lh=totalH-TOP_M;
      ctx.strokeRect(lx,ly,lw,lh);
      ctx.setLineDash([]);
      const fs=0.18;
      ctx.font=`${fs}px Segoe UI`;ctx.fillStyle='rgba(100,116,139,0.55)';
      ctx.textAlign='center';ctx.textBaseline='top';
      ctx.fillText(`${lw.toFixed(1)}m`,lx+lw/2,ly+0.08);
      if(lane.code){
        const cfs=0.16;
        ctx.font=`700 ${cfs}px Segoe UI`;
        ctx.fillStyle='rgba(30,58,95,0.55)';
        const shortCode=lane.code.length>12?lane.code.slice(0,11)+'…':lane.code;
        ctx.textAlign='center';ctx.textBaseline='bottom';
        ctx.fillText(shortCode,lx+lw/2,ly+lh-0.08);
      }
      ctx.font=`600 ${fs}px Segoe UI`;ctx.fillStyle='rgba(100,116,139,0.4)';
      ctx.textAlign='center';ctx.textBaseline='top';
      ctx.fillText(`L${li+1}`,lx+lw/2,ly+0.08+fs*1.2);
      ctx.setLineDash([0.3,0.2]);
    }
  }
  ctx.restore();
}

// ── Corridor markings ──
function drawCorridor(corrL,corrR,yTop,yBot){
  const cx=(corrL+corrR)/2;
  // Centre dash
  ctx.strokeStyle='#fbbf24';ctx.lineWidth=0.08;ctx.setLineDash([0.5,0.35]);
  ctx.beginPath();ctx.moveTo(cx,yTop);ctx.lineTo(cx,yBot);ctx.stroke();
  // Edge lines
  ctx.lineWidth=0.07;ctx.setLineDash([]);
  [corrL,corrR].forEach(lx=>{
    ctx.beginPath();ctx.moveTo(lx,yTop);ctx.lineTo(lx,yBot);ctx.stroke();
  });
  // N-S movement arrows in corridor (small & subtle)
  const nArr=Math.max(2,Math.floor((yBot-yTop)/8));
  ctx.globalAlpha=0.35;
  for(let i=0;i<nArr;i++){
    const ay=yTop+2+i*Math.max(2,(yBot-yTop-4)/(nArr-1||1));
    arrowV(corrL+1.5,ay,1.2,C.fklt,true);
    arrowV(corrR-1.5,ay,1.2,C.fklt,false);
  }
  ctx.globalAlpha=1;
  // Corridor label
  const fs=Math.min(0.35, CORR_W*0.045);
  ctx.font=`700 ${fs}px Segoe UI`;
  ctx.fillStyle='#0369a1';ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.setLineDash([]);
  ctx.fillText(`CORRIDOR ${CORR_W.toFixed(0)}m`,cx,yTop+0.5);
}

// ── Zone access arrows (south face of storage zones) ──
// Forklift leaves corridor → enters zones from SOUTH to access N-S long parts
function drawZoneAccess(corrL,corrR,totalW,zoneBottom){
  ctx.save();
  // Left zone: forklift turns WEST out of corridor at south
  ctx.strokeStyle=C.fklt;ctx.lineWidth=0.04;ctx.setLineDash([0.2,0.15]);
  ctx.globalAlpha=0.5;
  ctx.beginPath();ctx.moveTo(corrL,zoneBottom-0.5);ctx.lineTo(SIDE_M,zoneBottom-0.5);ctx.stroke();
  ctx.setLineDash([]);
  ctx.fillStyle=C.fklt;ctx.beginPath();
  ctx.moveTo(SIDE_M,zoneBottom-0.5);
  ctx.lineTo(SIDE_M+0.3,zoneBottom-0.5-0.12);ctx.lineTo(SIDE_M+0.3,zoneBottom-0.5+0.12);
  ctx.closePath();ctx.fill();
  // Label
  const fs=0.15;
  ctx.font=`${fs}px Segoe UI`;ctx.fillStyle=C.fklt;
  ctx.textAlign='center';ctx.textBaseline='bottom';
  ctx.fillText('Forklift entry (S face)',corrL/2,zoneBottom-0.55);
  // Right zone: forklift turns EAST
  ctx.strokeStyle=C.fklt;ctx.lineWidth=0.04;ctx.setLineDash([0.2,0.15]);
  ctx.beginPath();ctx.moveTo(corrR,zoneBottom-0.5);ctx.lineTo(totalW-SIDE_M,zoneBottom-0.5);ctx.stroke();
  ctx.setLineDash([]);
  ctx.fillStyle=C.fklt;ctx.beginPath();
  ctx.moveTo(totalW-SIDE_M,zoneBottom-0.5);
  ctx.lineTo(totalW-SIDE_M-0.3,zoneBottom-0.5-0.12);ctx.lineTo(totalW-SIDE_M-0.3,zoneBottom-0.5+0.12);
  ctx.closePath();ctx.fill();
  ctx.textAlign='center';
  ctx.fillText('Forklift entry (S face)',(corrR+totalW)/2,zoneBottom-0.55);
  ctx.globalAlpha=1;
  ctx.restore();
}

// ── Forklift paths: route from staging through corridor to each item ──
function drawForkPaths(corrL,corrR,totalW,totalH){
  if(!items.length)return;
  ctx.save();
  const corrCx=(corrL+corrR)/2;
  const stagingY=totalH+1.0;
  const pathColors=['#ef4444','#f97316','#eab308','#22c55e','#06b6d4','#3b82f6','#8b5cf6','#ec4899',
    '#f43f5e','#d946ef','#14b8a6','#84cc16','#fb923c','#a78bfa','#2dd4bf','#f87171'];
  let ci=0;
  const fw=0.10, fh=0.15;
  for(const it of items){
    const p=pos[it.id]; if(!p)continue;
    const{dW,dH}=getDD(it);
    const onL=layout.leftItems.has(it.id);
    const col=pathColors[ci%pathColors.length]; ci++;

    // Forklift approaches from the LONGEST side of the item
    // dH = N-S extent, dW = E-W extent
    const approachSide = dH >= dW; // true = long side is N-S → approach from E/W (corridor side)

    ctx.strokeStyle=col;ctx.lineWidth=0.04;ctx.globalAlpha=0.3;
    ctx.setLineDash([0.15,0.1]);

    if(approachSide){
      // LONG SIDE runs N-S → forklift comes from corridor side (E or W face)
      // Target: center of N-S length, on the corridor-facing edge
      const targetY=p.y+dH/2; // center of longest side
      const targetX=onL?(p.x+dW):(p.x); // corridor-side edge
      const corrEdge=onL?corrL:corrR;
      ctx.beginPath();
      ctx.moveTo(corrCx, stagingY);
      ctx.lineTo(corrCx, targetY);
      ctx.lineTo(corrEdge, targetY);
      ctx.lineTo(targetX, targetY);
      ctx.stroke();
      // Forklift triangle pointing into the zone (west for left, east for right)
      ctx.setLineDash([]);ctx.globalAlpha=0.6;ctx.fillStyle=col;
      if(onL){
        // Pointing west (into left zone)
        ctx.beginPath();
        ctx.moveTo(targetX+0.05, targetY);
        ctx.lineTo(targetX+0.05+fh, targetY-fw);
        ctx.lineTo(targetX+0.05+fh, targetY+fw);
        ctx.closePath();ctx.fill();
      } else {
        // Pointing east (into right zone)
        ctx.beginPath();
        ctx.moveTo(targetX-0.05, targetY);
        ctx.lineTo(targetX-0.05-fh, targetY-fw);
        ctx.lineTo(targetX-0.05-fh, targetY+fw);
        ctx.closePath();ctx.fill();
      }
    } else {
      // LONG SIDE runs E-W → forklift comes from south face
      // Target: center of E-W length, on the south face
      const targetX=p.x+dW/2; // center of longest side
      const targetY=p.y+dH;    // south face
      const corrSide=onL?corrL-0.3:corrR+0.3;
      ctx.beginPath();
      ctx.moveTo(corrCx, stagingY);
      ctx.lineTo(corrCx, targetY+0.5);
      ctx.lineTo(corrSide, targetY+0.5);
      ctx.lineTo(targetX, targetY+0.5);
      ctx.lineTo(targetX, targetY+0.08);
      ctx.stroke();
      // Forklift triangle pointing north
      ctx.setLineDash([]);ctx.globalAlpha=0.6;ctx.fillStyle=col;
      ctx.beginPath();
      ctx.moveTo(targetX, targetY+0.08);
      ctx.lineTo(targetX-fw, targetY+0.08+fh);
      ctx.lineTo(targetX+fw, targetY+0.08+fh);
      ctx.closePath();ctx.fill();
    }
  }
  ctx.globalAlpha=1;
  ctx.restore();
}

function arrowV(x,y,len,color,down){
  const hw=0.08,hl=0.16,ty=down?y+len:y-len;
  ctx.strokeStyle=color;ctx.lineWidth=0.04;ctx.setLineDash([0.2,0.15]);
  ctx.beginPath();ctx.moveTo(x,y);ctx.lineTo(x,ty);ctx.stroke();
  ctx.setLineDash([]);
  ctx.fillStyle=color;ctx.beginPath();
  if(down){ctx.moveTo(x,ty);ctx.lineTo(x-hw,ty-hl);ctx.lineTo(x+hw,ty-hl);}
  else    {ctx.moveTo(x,ty);ctx.lineTo(x-hw,ty+hl);ctx.lineTo(x+hw,ty+hl);}
  ctx.closePath();ctx.fill();
}

// ── Draw item ──
// Clean label: item code only + ×N badge. Dimensions on hover/panel.
function drawItem(it,x,y,dW,dH,fc,dc,sel){
  const{cols,rows,effStack}=getDD(it);
  const bW=it.W, bL=it.L; // single bundle size (W=E-W, L=N-S)
  const pxW=dW*zoom, pxH=dH*zoom;
  // Main fill
  ctx.fillStyle=fc;
  ctx.globalAlpha=sel?0.95:0.82;
  ctx.fillRect(x,y,dW,dH);
  ctx.globalAlpha=1;
  // ── Draw individual bundle cells ──
  ctx.save();
  ctx.beginPath();ctx.rect(x,y,dW,dH);ctx.clip();
  if(pxW>30&&pxH>30){
    // Bundle grid lines
    ctx.strokeStyle='rgba(255,255,255,0.35)';ctx.lineWidth=0.03;ctx.setLineDash([]);
    for(let c=1;c<cols;c++){
      const lx=x+c*bW;
      ctx.beginPath();ctx.moveTo(lx,y);ctx.lineTo(lx,y+dH);ctx.stroke();
    }
    for(let r=1;r<rows;r++){
      const ly=y+r*bL;
      ctx.beginPath();ctx.moveTo(x,ly);ctx.lineTo(x+dW,ly);ctx.stroke();
    }
    // Inner shadow per bundle cell (bottom-right edge)
    if(pxW>60&&pxH>60){
      ctx.strokeStyle='rgba(0,0,0,0.12)';ctx.lineWidth=0.02;
      for(let c=0;c<cols;c++){
        for(let r=0;r<rows;r++){
          const bx=x+c*bW, by=y+r*bL;
          // Bottom edge highlight
          ctx.beginPath();ctx.moveTo(bx+0.02,by+bL-0.02);ctx.lineTo(bx+bW-0.02,by+bL-0.02);ctx.stroke();
          // Right edge highlight
          ctx.beginPath();ctx.moveTo(bx+bW-0.02,by+0.02);ctx.lineTo(bx+bW-0.02,by+bL-0.02);ctx.stroke();
        }
      }
      // Top-left highlight (light) per cell
      ctx.strokeStyle='rgba(255,255,255,0.2)';ctx.lineWidth=0.02;
      for(let c=0;c<cols;c++){
        for(let r=0;r<rows;r++){
          const bx=x+c*bW, by=y+r*bL;
          ctx.beginPath();ctx.moveTo(bx+0.02,by+0.02);ctx.lineTo(bx+bW-0.02,by+0.02);ctx.stroke();
          ctx.beginPath();ctx.moveTo(bx+0.02,by+0.02);ctx.lineTo(bx+0.02,by+bL-0.02);ctx.stroke();
        }
      }
    }
    // Stack layer indicator — small stacked rectangles in top-left bundle
    if(effStack>1&&pxW>80&&pxH>80){
      const stackIndW=Math.min(bW*0.25,0.3);
      const stackIndH=Math.min(bL*0.2,0.2);
      const sx0=x+0.06, sy0=y+0.06;
      for(let s=0;s<Math.min(effStack,4);s++){
        const off=s*0.04;
        ctx.fillStyle=s===Math.min(effStack,4)-1?'rgba(255,255,255,0.7)':'rgba(255,255,255,0.25)';
        ctx.fillRect(sx0+off,sy0+off,stackIndW,stackIndH);
        ctx.strokeStyle='rgba(0,0,0,0.25)';ctx.lineWidth=0.015;
        ctx.strokeRect(sx0+off,sy0+off,stackIndW,stackIndH);
      }
    }
  }
  // Long item diagonal stripes (subtle)
  if(it.is_long&&pxW>40){
    ctx.strokeStyle='rgba(255,255,255,0.08)';ctx.lineWidth=0.04;ctx.setLineDash([]);
    const step=Math.max(0.3,bW*0.4);
    for(let d=-dH;d<dW+dH;d+=step){
      ctx.beginPath();ctx.moveTo(x+d,y);ctx.lineTo(x+d+dH*0.3,y+dH);ctx.stroke();
    }
  }
  ctx.restore();
  // Outer border
  ctx.strokeStyle=sel?'#f59e0b':dc;
  ctx.lineWidth=sel?0.13:0.06;
  ctx.setLineDash([]);
  ctx.strokeRect(x,y,dW,dH);
  if(sel){
    ctx.strokeStyle='#f59e0b';ctx.lineWidth=0.09;
    ctx.strokeRect(x-0.07,y-0.07,dW+0.14,dH+0.14);
  }
  // ── Label: rotate text to follow longest dimension ──
  if(pxW<10||pxH<10) return;
  ctx.save();
  ctx.beginPath();ctx.rect(x+0.04,y+0.04,dW-0.08,dH-0.08);ctx.clip();
  const rotateText = dH > dW*1.8;
  const textW = rotateText ? dH : dW;
  const textH = rotateText ? dW : dH;
  const pxTW = textW*zoom, pxTH = textH*zoom;
  const cx=x+dW/2, cy=y+dH/2;
  if(rotateText){
    ctx.translate(cx,cy);
    ctx.rotate(-Math.PI/2);
    ctx.translate(-cx,-cy);
  }
  // Stack badge
  if(pxTW>20&&pxTH>10){
    const bsz=Math.min(textH*0.22, textW*0.08, 0.35);
    if(bsz>0.08){
      ctx.font=`700 ${bsz}px Segoe UI`;
      ctx.fillStyle='rgba(255,255,255,0.88)';
      ctx.textAlign='right';ctx.textBaseline='top';
      const bx2=rotateText?cx+textW/2:x+dW;
      const by2=rotateText?cy-textH/2:y;
      ctx.fillText(`×${it.bundles} stk${effStack}`,bx2-0.04,by2+0.04);
    }
  }
  // Item name
  if(pxTW>18&&pxTH>8){
    const sz=Math.min(textH*0.28, textW*0.10, 0.45);
    if(sz>0.08){
      // Text shadow for readability
      ctx.font=`600 ${sz}px Segoe UI`;
      ctx.fillStyle='rgba(0,0,0,0.3)';ctx.textAlign='center';ctx.textBaseline='middle';
      const name=shortName(it.item);
      const measW=ctx.measureText(name).width;
      const lbl=measW<textW*0.9?name:name.slice(0,Math.max(4,Math.floor(textW/(sz*0.6))))+'…';
      ctx.fillText(lbl,cx+0.02,cy+0.02);
      ctx.fillStyle='#fff';
      ctx.fillText(lbl,cx,cy);
      // Subtext: grid and dims
      const subSz=sz*0.65;
      if(subSz>0.06&&pxTW>30){
        ctx.font=`${subSz}px Segoe UI`;
        ctx.fillStyle='rgba(255,255,255,0.7)';
        ctx.fillText(`${cols}×${rows} · ${it.L}×${it.W}m`,cx,cy+sz*1.1);
      }
    }
  }
  ctx.restore();
}

// ── Truck ──
function drawTruck(tx,ty){
  const tw=TRUCK_W, tl=TRUCK_L;
  ctx.fillStyle='#94a3b8';
  ctx.fillRect(tx,ty+0.3,tw,tl*0.70);
  ctx.strokeStyle='#475569';ctx.lineWidth=0.07;ctx.setLineDash([]);
  ctx.strokeRect(tx,ty+0.3,tw,tl*0.70);
  ctx.fillStyle='#64748b';
  ctx.fillRect(tx+tw*0.06,ty+tl*0.70+0.3,tw*0.88,tl*0.25);
  ctx.strokeRect(tx+tw*0.06,ty+tl*0.70+0.3,tw*0.88,tl*0.25);
  ctx.fillStyle='#1e293b';
  [[0.07,0.22],[0.65,0.22],[0.07,tl*0.44],[0.65,tl*0.44]].forEach(([rx,ry])=>{
    ctx.beginPath();
    ctx.ellipse(tx+rx*tw+tw*0.14,ty+ry+0.3,tw*0.08,0.24,0,0,Math.PI*2);
    ctx.fill();
  });
  const fs=Math.max(0.12,Math.min(0.24,tw*0.1));
  ctx.font=`700 ${fs}px Segoe UI`;
  ctx.fillStyle='#fff';ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText('TRUCK / TRAILER',tx+tw/2,ty+tl*0.37+0.3);
  // Approach arrow
  ctx.strokeStyle='#64748b';ctx.lineWidth=0.07;ctx.setLineDash([0.35,0.25]);
  ctx.beginPath();ctx.moveTo(tx+tw/2,ty+0.25);ctx.lineTo(tx+tw/2,ty-1.0);ctx.stroke();
  ctx.setLineDash([]);
  ctx.fillStyle='#64748b';ctx.beginPath();
  ctx.moveTo(tx+tw/2,ty-1.0);
  ctx.lineTo(tx+tw/2-0.18,ty-0.55);ctx.lineTo(tx+tw/2+0.18,ty-0.55);
  ctx.closePath();ctx.fill();
}

// ── Dimension lines — architectural construction drawing style ──
function drawDims(corrL,corrR,totalW,totalH){
  // Font size proportional to layout size — readable at any zoom
  const baseFs=Math.min(0.65, totalW*0.022, totalH*0.015);
  const dimC='#222';

  // ── OVERALL DIMENSIONS (outermost layer) ──
  dimLineCDW(0,totalH+STAGING+TRUCK_L+2.5,totalW,totalH+STAGING+TRUCK_L+2.5,
    totalW.toFixed(1)+'m',baseFs,dimC,'H',0.8);
  dimLineCDW(-2.5,TOP_M,-2.5,totalH,
    (totalH-TOP_M).toFixed(1)+'m',baseFs,dimC,'V',0.8);

  // ── ZONE BREAKDOWN (second layer) ──
  const ty=-1.2;
  const zfs=baseFs*0.92;
  const lw=corrL-SIDE_M;
  if(lw>0.5) dimLineCDW(SIDE_M,ty,corrL,ty,lw.toFixed(1),zfs,dimC,'H',0.5);
  dimLineCDW(corrL,ty,corrR,ty,CORR_W.toFixed(0),zfs,dimC,'H',0.5);
  const rw=totalW-corrR-SIDE_M;
  if(rw>0.5) dimLineCDW(corrR,ty,totalW-SIDE_M,ty,rw.toFixed(1),zfs,dimC,'H',0.5);

  // ── ITEM DIMENSIONS (per item — only W and H) ──
  const ifs=baseFs*0.72;
  const ic='rgba(80,100,120,0.5)';
  for(const it of items){
    const p=pos[it.id]; if(!p)continue;
    const{dW,dH}=getDD(it);
    const onL=layout.leftItems.has(it.id);
    if(dW>0.4) dimLineCDW(p.x,p.y-0.35,p.x+dW,p.y-0.35,dW.toFixed(1),ifs,ic,'H',0.15);
    if(dH>0.6){
      const dx=onL?p.x+dW+0.2:p.x-0.2;
      dimLineCDW(dx,p.y,dx,p.y+dH,dH.toFixed(1),ifs,ic,'V',0.12);
    }
  }

  // ── ROW CHAIN DIMENSIONS (right edge) ──
  const allRows=[...(layout.rightLanes||[]),...(layout.leftLanes||[])].filter(l=>l.isRow);
  if(allRows.length>1){
    const rx=totalW+1.2;
    for(const row of allRows){
      if(row.height>0.4) dimLineCDW(rx,row.y,rx,row.y+row.height,row.height.toFixed(1),ifs,ic,'V',0.1);
    }
  }
}

// Architectural dimension line: extension lines + solid line + tick marks
function dimLineCDW(x1,y1,x2,y2,lbl,fs,color,dir,ext){
  ctx.save();
  ctx.strokeStyle=color;ctx.fillStyle=color;
  const tk=Math.min(0.12, fs*0.5); // tick mark size
  if(dir==='H'){
    const my=y1;
    // Extension lines
    ctx.lineWidth=0.02;ctx.setLineDash([]);
    ctx.beginPath();ctx.moveTo(x1,my-ext);ctx.lineTo(x1,my+ext*0.3);ctx.stroke();
    ctx.beginPath();ctx.moveTo(x2,my-ext);ctx.lineTo(x2,my+ext*0.3);ctx.stroke();
    // Dimension line (solid)
    ctx.lineWidth=0.025;
    ctx.beginPath();ctx.moveTo(x1,my);ctx.lineTo(x2,my);ctx.stroke();
    // Tick marks (45° slash at each end)
    ctx.lineWidth=0.04;
    ctx.beginPath();ctx.moveTo(x1-tk,my+tk);ctx.lineTo(x1+tk,my-tk);ctx.stroke();
    ctx.beginPath();ctx.moveTo(x2-tk,my+tk);ctx.lineTo(x2+tk,my-tk);ctx.stroke();
    // Label centered above line with white background
    ctx.font=`600 ${fs}px Segoe UI`;ctx.textAlign='center';ctx.textBaseline='bottom';
    const tw=ctx.measureText(lbl).width;
    const pad=fs*0.15;
    ctx.fillStyle='rgba(255,255,255,0.92)';
    ctx.fillRect((x1+x2)/2-tw/2-pad, my-fs-0.12, tw+pad*2, fs+0.08);
    ctx.fillStyle=color;
    ctx.fillText(lbl,(x1+x2)/2,my-0.08);
  } else { // V
    const mx=x1;
    // Extension lines
    ctx.lineWidth=0.02;ctx.setLineDash([]);
    ctx.beginPath();ctx.moveTo(mx-ext,y1);ctx.lineTo(mx+ext*0.3,y1);ctx.stroke();
    ctx.beginPath();ctx.moveTo(mx-ext,y2);ctx.lineTo(mx+ext*0.3,y2);ctx.stroke();
    // Dimension line (solid)
    ctx.lineWidth=0.025;
    ctx.beginPath();ctx.moveTo(mx,y1);ctx.lineTo(mx,y2);ctx.stroke();
    // Tick marks (45 degree slash at each end)
    ctx.lineWidth=0.04;
    ctx.beginPath();ctx.moveTo(mx-tk,y1+tk);ctx.lineTo(mx+tk,y1-tk);ctx.stroke();
    ctx.beginPath();ctx.moveTo(mx-tk,y2+tk);ctx.lineTo(mx+tk,y2-tk);ctx.stroke();
    // Label (rotated, left of line) with white background
    ctx.font=`600 ${fs}px Segoe UI`;
    ctx.save();ctx.translate(mx-0.15,(y1+y2)/2);ctx.rotate(-Math.PI/2);
    ctx.textAlign='center';ctx.textBaseline='bottom';
    const twV=ctx.measureText(lbl).width;
    const padV=fs*0.15;
    ctx.fillStyle='rgba(255,255,255,0.92)';
    ctx.fillRect(-twV/2-padV, -fs-0.04, twV+padV*2, fs+0.08);
    ctx.fillStyle=color;
    ctx.fillText(lbl,0,0);
    ctx.restore();
  }
  ctx.restore();
}

// ── Zone labels ──
function drawZoneLabels(corrL,corrR,totalW,totalH){
  const fs=Math.min(0.4, totalW*0.018, TOP_M*0.45);
  ctx.setLineDash([]);
  ctx.font=`700 ${fs}px Segoe UI`;ctx.textBaseline='middle';
  const isTypeSplit=curStrat==='typeSplit';
  ctx.fillStyle='#1d4ed8';ctx.textAlign='center';
  ctx.fillText(isTypeSplit?'LEFT — LONG PARTS':'LEFT STORAGE',corrL/2,TOP_M*0.5);
  ctx.fillStyle='#065f46';ctx.textAlign='center';
  ctx.fillText(isTypeSplit?'RIGHT — BOX ITEMS':'RIGHT STORAGE',(corrR+totalW)/2,TOP_M*0.5);
  ctx.font=`600 ${fs*0.8}px Segoe UI`;
  ctx.fillStyle='#92400e';ctx.textAlign='center';
  ctx.fillText('WORKING ZONE',(corrL+corrR)/2,totalH+1.5);
}

// ── North Arrow ──
function drawNorth(cx,cy){
  const sz=0.5;
  ctx.fillStyle='#1e293b';
  ctx.beginPath();ctx.moveTo(cx,cy-sz);ctx.lineTo(cx-sz*0.38,cy+sz*0.3);ctx.lineTo(cx,cy);ctx.closePath();ctx.fill();
  ctx.fillStyle='#94a3b8';
  ctx.beginPath();ctx.moveTo(cx,cy-sz);ctx.lineTo(cx+sz*0.38,cy+sz*0.3);ctx.lineTo(cx,cy);ctx.closePath();ctx.fill();
  ctx.font=`700 ${sz*0.5}px Segoe UI`;ctx.fillStyle='#1e293b';
  ctx.textAlign='center';ctx.textBaseline='bottom';
  ctx.fillText('N',cx,cy-sz-0.08);
}

// ── Scale Bar ──
function drawScale(){
  // Screen-space scale bar (bottom-right, above zoom buttons)
  ctx.save();
  ctx.setTransform(dpr,0,0,dpr,0,0);
  const barLen=120; // px total
  const barH=6;
  const sx=cvsW-barLen-60, sy=cvsH-42;
  const segW=barLen/4;
  // Alternating segments
  for(let i=0;i<4;i++){
    ctx.fillStyle=i%2===0?'#334155':'#e2e8f0';
    ctx.fillRect(sx+i*segW,sy,segW,barH);
  }
  ctx.strokeStyle='#334155';ctx.lineWidth=1;ctx.setLineDash([]);
  ctx.strokeRect(sx,sy,barLen,barH);
  // End ticks
  [0,1,2,3,4].forEach(i=>{
    ctx.beginPath();ctx.moveTo(sx+i*segW,sy-2);ctx.lineTo(sx+i*segW,sy+barH+2);ctx.stroke();
  });
  // Compute real-world distance for the bar
  const realM=barLen/zoom;
  // Pick nice round number
  const niceVals=[0.5,1,2,5,10,20,50,100,200];
  let bestNice=realM;
  for(const n of niceVals){if(n<=realM*1.2){bestNice=n;}}
  const niceBarPx=bestNice*zoom;
  const niceSegPx=niceBarPx/4;
  // Redraw with nice values
  ctx.clearRect(sx-5,sy-14,barLen+20,barH+28);
  // Background
  ctx.fillStyle='rgba(255,255,255,0.85)';
  ctx.fillRect(sx-4,sy-12,niceBarPx+8,barH+24);
  for(let i=0;i<4;i++){
    ctx.fillStyle=i%2===0?'#334155':'#cbd5e1';
    ctx.fillRect(sx+i*niceSegPx,sy,niceSegPx,barH);
  }
  ctx.strokeStyle='#334155';ctx.lineWidth=1;
  ctx.strokeRect(sx,sy,niceBarPx,barH);
  [0,2,4].forEach(i=>{
    const px=sx+i*niceSegPx;
    ctx.beginPath();ctx.moveTo(px,sy-3);ctx.lineTo(px,sy+barH+3);ctx.stroke();
  });
  // Labels
  ctx.font='600 9px Segoe UI';ctx.fillStyle='#334155';ctx.textBaseline='top';
  ctx.textAlign='center';
  ctx.fillText('0',sx,sy+barH+4);
  ctx.fillText((bestNice/2).toFixed(bestNice<2?1:0)+'m',sx+niceBarPx/2,sy+barH+4);
  ctx.fillText(bestNice.toFixed(bestNice<2?1:0)+'m',sx+niceBarPx,sy+barH+4);
  ctx.restore();
}

// ══════════════════════ INTERACTION ══════════════════════
cvs.addEventListener('mousedown',e=>{
  // Check for footprint stack mode button clicks
  if(viewFP){
    const cy=e.offsetY;
    if(cy>=46 && cy<66){
      const cx=e.offsetX;
      const W=cvsW;
      const btnW=130, btnH=20, btnGap=10;
      const btnX=W/2-((btnW*2+btnGap)/2);
      for(let i=0;i<2;i++){
        const bx=btnX+i*(btnW+btnGap);
        if(cx>=bx && cx<bx+btnW){
          fpStackMode=i;
          draw();
          e.preventDefault();
          return;
        }
      }
    }
  }

  // Only do world-coordinate hit test in 2D layout mode
  if(curTab==='2d'){
    const{wx,wy}=toW(e);
    const hit=hitTest(wx,wy);
    if(hit){
      if(e.button===0){
        isDrag=true;dragId=hit.id;
        dsMx=e.clientX;dsMy=e.clientY;
        dsIx=pos[hit.id].x;dsIy=pos[hit.id].y;
        cvs.classList.add('drag');
      }
      selId=hit.id;updateSelPanel();buildIList();draw();
      e.preventDefault();return;
    }
  }
  // Hit test for Bundle Detail view — click on S/N box
  if(viewBD){
    const cx=e.offsetX,cy=e.offsetY;
    // If popup is open, click anywhere closes it
    if(bdPopup){
      bdPopup=null; draw(); e.preventDefault(); return;
    }
    // Check S/N box click zones
    for(const z of _bdClickZones){
      if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){
        bdPopup={...z, px:cx+10, py:cy-20};
        draw(); e.preventDefault(); return;
      }
    }
  }
  // Hit test for Truck Load view — click on loaded item
  if(viewTL&&_tlClickZones.length){
    const cx=e.offsetX,cy=e.offsetY;
    for(const z of _tlClickZones){
      if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){
        const it=items.find(i=>i.item===z.item);
        if(it){selId=it.id;updateSelPanel();buildIList();draw();}
        e.preventDefault();return;
      }
    }
  }
  // Hit test for Footprint view — click on treemap rect
  if(viewFP&&_fpClickZones.length){
    const cx=e.offsetX,cy=e.offsetY;
    for(const z of _fpClickZones){
      if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){
        const it=items.find(i=>i.item===z.item);
        if(it){selId=it.id;updateSelPanel();buildIList();draw();}
        e.preventDefault();return;
      }
    }
  }
  // Hit test for 3D view — click on item bounding box (reverse order for front items first)
  if(view3d&&window._3dClickZones&&window._3dClickZones.length){
    const cx=e.offsetX,cy=e.offsetY;
    for(let zi=window._3dClickZones.length-1;zi>=0;zi--){
      const z=window._3dClickZones[zi];
      if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){
        selId=z.id;updateSelPanel();buildIList();draw();
        e.preventDefault();return;
      }
    }
  }
  if(e.button===0||e.button===1){
    isPan=true;pMx=e.clientX;pMy=e.clientY;
    if(view3d){
      if(e.shiftKey||e.button===1){
        // Shift+drag or middle-click = pan in 3D
        pCx=iso3dPanX;pCy=iso3dPanY;
        iso3dDragging=false;
      } else {
        // Normal drag in 3D = orbit (horizontal only)
        iso3dDragging=true;
        iso3dDragStartA=iso3dAngle;
      }
    } else {
      pCx=camX;pCy=camY;
    }
    cvs.style.cursor='grabbing';
  }
});
cvs.addEventListener('mousemove',e=>{
  if(isDrag&&dragId){
    const dx=(e.clientX-dsMx)/zoom,dy=(e.clientY-dsMy)/zoom;
    pos[dragId]={x:dsIx+dx,y:dsIy+dy};
    draw();return;
  }
  if(isPan){
    if(view3d){
      if(iso3dDragging){
        // Orbit: horizontal mouse → angle only (fixed elevation)
        iso3dAngle=iso3dDragStartA+(e.clientX-pMx)*0.005;
      } else {
        iso3dPanX=pCx+(e.clientX-pMx);
        iso3dPanY=pCy+(e.clientY-pMy);
      }
    } else {
      camX=pCx+(e.clientX-pMx);
      camY=pCy+(e.clientY-pMy);
    }
    draw();return;
  }
  const{wx,wy}=toW(e);
  const hit=hitTest(wx,wy);
  const tip=document.getElementById('tip');
  if(hit){
    const{dW,dH}=getDD(hit);
    const{fp}=getDD(hit);
    const maxByFork=Math.max(1,Math.floor(FORK_MAX_H/hit.H));
    const effSt=Math.min(hit.stack,maxByFork);
    const realSH=(hit.H*Math.min(effSt,hit.bundles)).toFixed(2);
    const snsList=hit._allSns&&hit._allSns.length?hit._allSns.join(', '):'—';
    const contList=hit._containers&&hit._containers.length?hit._containers.join(', '):'—';
    tip.innerHTML=`<b style="color:#93c5fd">${hit.item}</b><br>`+
      `Size: ${hit.size}<br>`+
      `L=${hit.L}m  W=${hit.W}m  H=${hit.H}m<br>`+
      `Bundles: <b>${hit.bundles}</b>  Stack: ×${effSt} <span style="color:#fbbf24">(max ${FORK_MAX_H}m lift)</span><br>`+
      `Floor pos: ${fp}  ·  Footprint: ${dW.toFixed(2)}×${dH.toFixed(2)}m<br>`+
      `Stack height: <b>${realSH} m</b> / ${FORK_MAX_H}m limit<br>`+
      `<span style="color:#86efac">Container:</span> ${contList}<br>`+
      `<span style="color:#fde68a">S/N:</span> <span style="font-size:9px">${snsList}</span>`+
      (hit.rotated?'<br><span style="color:#fbbf24">↻ Rotated</span>':'');
    tip.style.display='block';
    tip.style.left=(e.offsetX+14)+'px';
    tip.style.top=(e.offsetY-12)+'px';
  } else {
    tip.style.display='none';
  }
});
cvs.addEventListener('mouseup',()=>{
  isDrag=false;dragId=null;isPan=false;iso3dDragging=false;
  cvs.classList.remove('drag');cvs.style.cursor='grab';
});
cvs.addEventListener('wheel',e=>{
  e.preventDefault();
  // Handle truck load view scrolling
  if(viewTL){
    tlScrollY+=e.deltaY>0?40:-40;
    if(tlScrollY<0)tlScrollY=0;
    draw();return;
  }
  // Handle bundle detail view scrolling
  if(viewBD){
    bdPopup=null; // close popup on scroll
    bdScrollY+=e.deltaY>0?40:-40;
    draw();return;
  }
  if(viewRpt){
    rptScrollY+=e.deltaY>0?40:-40;
    if(rptScrollY<0)rptScrollY=0;
    draw();return;
  }
  // Handle footprint view scrolling (table side)
  if(viewFP){
    const scrollAmount=e.deltaY>0?30:-30;
    fpScrollY+=scrollAmount;
    if(fpScrollY<0)fpScrollY=0;
    draw();
    return;
  }
  // Handle 3D zoom
  if(view3d){
    const f=e.deltaY<0?1.1:1/1.1;
    iso3dZoom=Math.max(0.2,Math.min(5,iso3dZoom*f));
    draw();return;
  }
  // Handle canvas zoom for 2D view
  const f=e.deltaY<0?1.1:1/1.1;
  const mx=e.offsetX,my=e.offsetY;
  const wx=(mx-camX)/zoom,wy=(my-camY)/zoom;
  zoom*=f;camX=mx-wx*zoom;camY=my-wy*zoom;
  draw();
},{passive:false});
cvs.addEventListener('mouseleave',()=>{
  isDrag=false;isPan=false;iso3dDragging=false;
  document.getElementById('tip').style.display='none';
  cvs.style.cursor='grab';
});
function toW(e){
  const r=cvs.getBoundingClientRect();
  return{wx:(e.clientX-r.left-camX)/zoom,wy:(e.clientY-r.top-camY)/zoom};
}
function hitTest(wx,wy){
  for(let i=items.length-1;i>=0;i--){
    const it=items[i],p=pos[it.id];
    if(!p)continue;
    const{dW,dH}=getDD(it);
    if(wx>=p.x&&wx<=p.x+dW&&wy>=p.y&&wy<=p.y+dH)return it;
  }
  return null;
}

// ══════════════════════ SCENARIO ══════════════════════
function setSc(v,idx){
  sc=v;
  [0,1,2,3,4].forEach(i=>{const el=document.getElementById('sc'+i);if(el)el.classList.remove('on');});
  document.getElementById('sc'+idx).classList.add('on');
  // Show/hide multi-ship section
  const multiSec=document.getElementById('multiSec');
  const multiContSec=document.getElementById('multiContSec');
  if(multiSec) multiSec.style.display=v==='multi'?'':'none';
  if(multiContSec) multiContSec.style.display=v==='multiCont'?'':'none';
  if(v==='multi') buildMultiChk();
  else if(v==='multiCont') buildMultiContChk();
  else onShip();
}
function buildMultiChk(){
  const el=document.getElementById('multiChk');
  el.innerHTML=ships.map((s,i)=>`
    <label style="display:flex;align-items:center;gap:5px;padding:3px 4px;font-size:10.5px;cursor:pointer">
      <input type="checkbox" class="shipChk" value="${i}">
      Ship ${s.id} (${s.containers.length} cont · ${s.containers.reduce((t,c)=>t+c.total_bundles,0)} bdl)
    </label>
  `).join('');
}
function loadMulti(){
  const checks=document.querySelectorAll('.shipChk:checked');
  if(!checks.length){alert('Select at least one shipment');return;}
  let raw=[];
  checks.forEach(chk=>{
    const si=+chk.value;
    const s=ships[si];
    if(s) s.containers.forEach((c,ci)=>c.items.forEach((_,ii)=>{
      raw.push({...itemMap[`s${si}c${ci}i${ii}`]});
    }));
  });
  items=consolidate(raw);
  pos={};selId=null;layout=null;
  buildIList();updatePklist();
  runAI();
}
