// Merge items with same part code into ONE block (combined bundles)
function consolidate(arr){
  const m={};
  for(const it of arr){
    const k=it.item;
    if(!m[k]){
      m[k]={...it, bundles:0, sqm:0, _srcIds:[], _allSns:[], _containers:[]};
    }
    m[k].bundles+=it.bundles;
    m[k].sqm+=it.sqm;
    m[k]._srcIds.push(it.id);
    // Merge S/N tracking
    if(it.sns&&it.sns.length) m[k]._allSns.push(...it.sns);
    // Track source container
    const ship=ships[it.si];
    const cont=ship&&ship.containers[it.ci];
    if(cont) m[k]._containers.push(cont.id);
  }
  let idx=0;
  const res=[];
  for(const[code,it]of Object.entries(m)){
    it.id='m'+idx; it.floor_pos=Math.ceil(it.bundles/it.stack);
    // Deduplicate containers
    it._containers=[...new Set(it._containers)];
    it._allSns.sort((a,b)=>a-b);
    idx++;
    res.push(it);
  }
  return res;
}
function loadScenario(){
  const sv=document.getElementById('shipSel').value;
  const cv=document.getElementById('contSel').value;
  let raw=[];
  if(sc==='container'){
    const si=sv!==''?+sv:0, ci=cv!==''?+cv:0;
    const c=ships[si]&&ships[si].containers[ci];
    if(c) raw=c.items.map((_,ii)=>({...itemMap[`s${si}c${ci}i${ii}`]}));
  } else if(sc==='shipment'){
    const si=sv!==''?+sv:0;
    const s=ships[si];
    if(s) s.containers.forEach((c,ci)=>c.items.forEach((_,ii)=>{
      raw.push({...itemMap[`s${si}c${ci}i${ii}`]});
    }));
  } else {
    Object.values(itemMap).forEach(it=>raw.push({...it}));
  }
  // Consolidate same part codes into single blocks
  items=consolidate(raw);
  pos={};selId=null;layout=null;
  // Pre-compute report data (GB/T analysis) once — NOT on every frame
  buildReportCache(raw);
  buildIList();updatePklist();
  runAI();
}

// ── Pre-compute report cache for GB/T + area analysis ──
var rptCache=null;
// ── Truck trip cache: computed once per scenario/layout, reused by report + truck view ──
let _truckTripsCache=null, _truckTripsDirty=true;
function invalidateTruckTrips(){_truckTripsDirty=true;_truckTripsCache=null;}
function getCachedTruckTrips(){
  if(!_truckTripsDirty&&_truckTripsCache) return _truckTripsCache;
  _truckTripsCache=planTruckTrips();
  _truckTripsDirty=false;
  return _truckTripsCache;
}

function buildReportCache(rawItems){
  let totalGBpcs=0, totalNonGBpcs=0;
  const gbFamilies={};
  const matGBdata={};

  // Scan raw items (NOT consolidated) for sn_contents
  for(const it of rawItems){
    const sc2=it.sn_contents;
    if(!sc2) continue;
    const mKey=it.item;
    if(!matGBdata[mKey]) matGBdata[mKey]={gb:0,ngb:0,area:it.sqm||0};
    else matGBdata[mKey].area+=(it.sqm||0);
    for(const[snk,contents] of Object.entries(sc2)){
      for(const ci of contents){
        const dim=ci.dim||'';
        const qty=ci.qty||0;
        const isGB=dim&&(dim.indexOf('GB/T')>=0||dim.indexOf('CB/T')>=0);
        if(isGB){
          totalGBpcs+=qty;
          matGBdata[mKey].gb+=qty;
          const parts=dim.split(/\s+/);
          const std=parts.length>=2?parts[0]+' '+parts[1]:dim;
          if(!gbFamilies[std]) gbFamilies[std]={qty:0,specs:new Set()};
          gbFamilies[std].qty+=qty;
          gbFamilies[std].specs.add(dim);
        } else {
          totalNonGBpcs+=qty;
          matGBdata[mKey].ngb+=qty;
        }
      }
    }
  }

  // Proportional area split
  let gbArea=0, structArea=0;
  for(const[k,md] of Object.entries(matGBdata)){
    const tot=md.gb+md.ngb;
    if(tot>0&&md.area>0){
      gbArea+=md.area*md.gb/tot;
      structArea+=md.area*md.ngb/tot;
    } else if(md.area>0){ structArea+=md.area; }
  }

  // Convert Sets to counts for storage
  const famArr=Object.entries(gbFamilies).map(([std,f])=>({std,qty:f.qty,specs:f.specs.size})).sort((a,b)=>b.qty-a.qty);

  rptCache={
    totalGBpcs, totalNonGBpcs,
    totalAllPcs: totalGBpcs+totalNonGBpcs,
    gbPct: (totalGBpcs+totalNonGBpcs)>0?(totalGBpcs/(totalGBpcs+totalNonGBpcs)*100):0,
    gbArea, structArea,
    gbFamilies: famArr
  };
}

