function selItem(id){
  selId=id;updateSelPanel();buildIList();
  if(viewBD){
    // Scroll BD view to show the selected item
    scrollBDtoItem(id);
  } else {
    const it=items.find(i=>i.id===id);
    if(it&&pos[id]){
      const{dW,dH}=getDD(it),p=pos[id];
      camX=cvsW/2-(p.x+dW/2)*zoom;
      camY=cvsH/2-(p.y+dH/2)*zoom;
    }
  }
  draw();
}
function scrollBDtoItem(id){
  // Calculate vertical offset to the first occurrence of item in BD containers
  if(!ships.length) return;
  const containers=getBDContainers();
  if(!containers.length) return;
  const contHdrH=28, itemHdrH=22, boxH=52, boxGap=4, itemPadBot=6, pad=14;
  const maxBoxCols=Math.floor((cvsW-pad*2-8)/(62+4));
  let cy=10+8; // contentTop+8 offset
  for(const c of containers){
    cy+=contHdrH;
    for(const it of c.items){
      let hasGB=false;
      if(it.sn_contents){
        const fk=Object.keys(it.sn_contents)[0];
        if(fk){const fc=it.sn_contents[fk][0];if(fc&&fc.dim&&/^GB\/T/.test(fc.dim)) hasGB=true;}
      }
      const hdrH=hasGB?itemHdrH+10:itemHdrH;
      if(it.item===id||it._matchId===id){
        // Found! Scroll so this item is near top
        bdScrollY=Math.max(0,cy-50);
        return;
      }
      // Check if any item in this container matches by item name
      const selIt=items.find(i=>i.id===id);
      if(selIt&&it.item===selIt.item){
        bdScrollY=Math.max(0,cy-50);
        return;
      }
      cy+=hdrH;
      const bRows=Math.ceil(it.bundles/maxBoxCols);
      cy+=bRows*(boxH+boxGap)+itemPadBot;
    }
    cy+=10;
  }
}
function getBDContainers(){
  // Get containers for BD view based on current scenario
  const sv=document.getElementById('shipSel').value;
  const cs=document.getElementById('contSel').value;
  let containers=[];
  if(sc==='container'&&sv!==''&&cs!==''){
    const ship=ships[+sv];
    const cont=ship.containers[+cs];
    if(cont) containers=[{id:cont.id,ship:ship.id,items:cont.items}];
  } else if(sc==='shipment'&&sv!==''){
    const ship=ships[+sv];
    containers=ship.containers.map(c=>({id:c.id,ship:ship.id,items:c.items}));
  } else if(sc==='all'){
    for(const ship of ships){
      for(const c of ship.containers){
        containers.push({id:c.id,ship:ship.id,items:c.items});
      }
    }
  }
  return containers;
}
