function updateMetrics(){
  const el=document.getElementById('metrics');
  if(!layout){el.innerHTML='<div class="empty">Select a scenario</div>';return;}
  const{corrL,corrR,totalW,totalH}=layout;
  const lw=corrL-SIDE_M, rw=totalW-corrR-SIDE_M;
  // ── Detailed area breakdown ──
  // 1. Material area: actual item footprints on ground
  const materialArea=items.reduce((s,it)=>{const{dW,dH}=getDD(it);return s+dW*dH;},0);
  // 2. Zone area: L+R zone rectangles (includes gaps between items)
  const leftZoneArea=lw*(totalH-TOP_M);
  const rightZoneArea=rw*(totalH-TOP_M);
  const zoneArea=leftZoneArea+rightZoneArea;
  const gapArea=zoneArea-materialArea; // wasted space in zones (lane gaps, margins)
  // 3. Corridor area (= drive lane + working zone)
  const corridorArea=CORR_W*totalH;
  // 4. Margin area (side margins + top margin)
  const marginArea=totalW*totalH - zoneArea - corridorArea;
  // 5. Total storage envelope
  const storageArea=totalW*totalH;
  // 6. Rental estimate (storage + working zone for truck)
  const workingZoneArea=CORR_W*(TRUCK_L+2);
  const rentalArea=storageArea+workingZoneArea;
  const util=zoneArea>0?(materialArea/zoneArea*100).toFixed(0):0;
  // Forklift travel
  let totalTravel=0;
  for(const it of items){
    const p=pos[it.id]; if(!p)continue;
    const{dW,dH}=getDD(it);
    const cy=p.y+dH/2;
    const dist=totalH-cy+1.0;
    totalTravel+=dist*it.bundles;
  }
  const avgTrip=items.length>0?(totalTravel/items.reduce((s,i)=>s+i.bundles,0)).toFixed(1):'0';
  const stratName=document.getElementById('stratSel').selectedOptions[0].text;
  const pct=(v,t)=>t>0?((v/t)*100).toFixed(0)+'%':'0%';
  // Get current scenario name for status bar
  let scenarioName='Scenario';
  const shipSel=document.getElementById('shipSel');
  const contSel=document.getElementById('contSel');
  if(shipSel.value!==''){
    const ship=ships[+shipSel.value];
    if(ship){
      if(contSel.value!==''){
        const cont=ship.containers[+contSel.value];
        scenarioName=`${ship.name} · ${cont.id}`;
      } else {
        scenarioName=ship.name;
      }
    }
  }
  el.innerHTML=`
    <div class="mc"><div class="mcl">YOU NEED TO RENT</div>
      <span class="mcv">${rentalArea.toFixed(0)}</span><span class="mcu">m²</span></div>
    <div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:4px;padding:6px 8px;margin-bottom:4px">
      <div style="font-size:8.5px;color:#16a34a;font-weight:700;letter-spacing:.5px;text-transform:uppercase;margin-bottom:4px">AREA BREAKDOWN</div>
      <div class="ms" style="border-color:#bbf7d0"><span class="msl">📦 Material on ground</span><span class="msv" style="color:#16a34a">${materialArea.toFixed(1)} m²</span></div>
      <div class="ms" style="border-color:#bbf7d0"><span class="msl">↔ Lane gaps / margins</span><span class="msv">${gapArea.toFixed(1)} m²</span></div>
      <div class="ms" style="border-color:#bbf7d0"><span class="msl">🚗 Corridor (drive lane)</span><span class="msv">${corridorArea.toFixed(1)} m²</span></div>
      <div class="ms" style="border-color:#bbf7d0"><span class="msl">🔧 Working zone (truck)</span><span class="msv">${workingZoneArea.toFixed(1)} m²</span></div>
      <div class="ms" style="border-color:#bbf7d0;background:#f0fdf4"><span class="msl"><b>Total rental</b></span><span class="msv hi"><b>${rentalArea.toFixed(1)} m²</b></span></div>
    </div>
    <div style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:4px;padding:6px 8px;margin-bottom:4px">
      <div style="font-size:8.5px;color:#2563eb;font-weight:700;letter-spacing:.5px;text-transform:uppercase;margin-bottom:4px">% BREAKDOWN</div>
      <div class="ms" style="border-color:#bfdbfe"><span class="msl">Material</span><span class="msv">${pct(materialArea,rentalArea)}</span></div>
      <div class="ms" style="border-color:#bfdbfe"><span class="msl">Gaps/margins</span><span class="msv">${pct(gapArea+marginArea,rentalArea)}</span></div>
      <div class="ms" style="border-color:#bfdbfe"><span class="msl">Drive + work</span><span class="msv">${pct(corridorArea+workingZoneArea,rentalArea)}</span></div>
    </div>
    <div class="ms"><span class="msl">Strategy</span><span class="msv hi" style="font-size:9px">${stratName}</span></div>
    <div class="ms"><span class="msl">Dimensions</span><span class="msv">${totalW.toFixed(1)} × ${totalH.toFixed(1)} m</span></div>
    <div class="ms"><span class="msl">L zone / R zone</span><span class="msv">${lw.toFixed(1)}m / ${rw.toFixed(1)}m</span></div>
    <div class="ms"><span class="msl">Zone utilisation</span><span class="msv">${util}%</span></div>
    <div class="ms"><span class="msl">Avg forklift trip</span><span class="msv">${avgTrip} m</span></div>
    <div class="ms"><span class="msl">Items placed</span><span class="msv">${Object.keys(pos).length} / ${items.length}</span></div>
  `;
  document.getElementById('ibar').textContent=
    `${scenarioName} · ${stratName} · Material: ${materialArea.toFixed(0)}m² · Drive: ${corridorArea.toFixed(0)}m² · Rent: ${rentalArea.toFixed(0)}m² · Trip: ${avgTrip}m`;
}
