  // ═══════════════════ SECTION: RENTAL RECOMMENDATION ═══════════════════
  pdf.addPage(); secNum++;
  secTitle(secNum,'Warehouse Rental Area Recommendation — 21-Shipment Analysis');
  ty=22;

  // Sub-header
  pdf.setFontSize(8);pdf.setTextColor(100);
