  // ── Big answer boxes ─────────────────────────────────────────────────
  pdf.setFillColor(239,246,255);pdf.rect(10,ty,120,20,'F');
  pdf.setDrawColor(37,99,235);pdf.setLineWidth(0.8);pdf.rect(10,ty,120,20,'D');
