// ══════════════════════ 3D ISOMETRIC VIEW ══════════════════════
function draw3D(){
  const W=cvsW, H=cvsH;
  ctx.clearRect(0,0,W,H);
  // Background
  ctx.fillStyle='#e8ecf1';ctx.fillRect(0,0,W,H);
  ctx.save();
  if(!layout) {ctx.restore(); return;}
  const{corrL,corrR,totalW,totalH}=layout;
  const floorD=totalH+5; // floor depth including working zone

  // Isometric helpers with orbit — angle and elevation from user drag
  const cosA=Math.cos(iso3dAngle), sinA=Math.sin(iso3dAngle);
  const cosE=Math.cos(iso3dElev), sinE=Math.sin(iso3dElev);
  const baseScX=W/(totalW+floorD+8)*0.85;
  const baseScY=H/((totalW+floorD)*sinE+12)*0.75;
  const isoSc=Math.min(baseScX,baseScY)*iso3dZoom;

  // Project 3D → 2D with orbit: x right, y into screen, z up
  function proj(x3,y3,z3){
    const rx=x3*cosA - y3*sinA;
    const ry=x3*sinA + y3*cosA;
    return {sx: rx*isoSc, sy: (ry*sinE - (z3||0))*isoSc};
  }

  // Compute bounding box to center
  const corners=[[0,0],[totalW,0],[0,floorD],[totalW,floorD]];
  let minSx=Infinity,maxSx=-Infinity,minSy=Infinity,maxSy=-Infinity;
  for(const[cx,cy]of corners){
    const{sx,sy}=proj(cx,cy,0);
    minSx=Math.min(minSx,sx);maxSx=Math.max(maxSx,sx);
    const{sy:sy5}=proj(cx,cy,5);
    minSy=Math.min(minSy,sy5);maxSy=Math.max(maxSy,sy);
  }
  const ox=W/2-(minSx+maxSx)/2+iso3dPanX;
  const oy=H*0.45-(minSy+maxSy)/2+iso3dPanY;

  function isoX(x,y){return ox+proj(x,y,0).sx;}
  function isoY(x,y,z){return oy+proj(x,y,z||0).sy;}

  function drawFace(pts,fill,edge){
    ctx.fillStyle=fill;ctx.beginPath();
    ctx.moveTo(pts[0][0],pts[0][1]);
    for(let i=1;i<pts.length;i++) ctx.lineTo(pts[i][0],pts[i][1]);
    ctx.closePath();ctx.fill();
    ctx.strokeStyle=edge||'rgba(0,0,0,0.45)';ctx.lineWidth=1.2;ctx.stroke();
  }

  // Determine which side faces are visible based on orbit angle
  const showFront=sinA>=0;
  const showBack=sinA<0;
  const showRight=cosA>=0;
  const showLeft=cosA<0;

  function drawBox(x,y,w,d,h,topC,frontC,sideC,zB){
    if(h<0.01) return;
    const z0=zB||0, z1=z0+h;
    const edge='rgba(0,0,0,0.5)';
    // Darker shade for hidden-side faces to give depth
    const darkFront=shadeColor(frontC,-20);
    const darkSide=shadeColor(sideC,-20);

    // ALWAYS draw ALL 6 faces — back faces first, front faces last (painter's algorithm)
    // 1. Bottom face
    drawFace([
      [isoX(x,y),isoY(x,y,z0)],[isoX(x+w,y),isoY(x+w,y,z0)],
      [isoX(x+w,y+d),isoY(x+w,y+d,z0)],[isoX(x,y+d),isoY(x,y+d,z0)]
    ],darkSide,edge);
    // 2. Back -Y face (draw always, use darker shade when it's the "hidden" side)
    drawFace([
      [isoX(x,y),isoY(x,y,z1)],[isoX(x+w,y),isoY(x+w,y,z1)],
      [isoX(x+w,y),isoY(x+w,y,z0)],[isoX(x,y),isoY(x,y,z0)]
    ],showBack?frontC:darkFront,edge);
    // 3. Left -X face
    drawFace([
      [isoX(x,y),isoY(x,y,z1)],[isoX(x,y+d),isoY(x,y+d,z1)],
      [isoX(x,y+d),isoY(x,y+d,z0)],[isoX(x,y),isoY(x,y,z0)]
    ],showLeft?sideC:darkSide,edge);
    // 4. Front +Y face
    drawFace([
      [isoX(x,y+d),isoY(x,y+d,z1)],[isoX(x+w,y+d),isoY(x+w,y+d,z1)],
      [isoX(x+w,y+d),isoY(x+w,y+d,z0)],[isoX(x,y+d),isoY(x,y+d,z0)]
    ],showFront?frontC:darkFront,edge);
    // 5. Right +X face
    drawFace([
      [isoX(x+w,y),isoY(x+w,y,z1)],[isoX(x+w,y+d),isoY(x+w,y+d,z1)],
      [isoX(x+w,y+d),isoY(x+w,y+d,z0)],[isoX(x+w,y),isoY(x+w,y,z0)]
    ],showRight?sideC:darkSide,edge);
    // 6. Top face always last (always visible from above)
    drawFace([
      [isoX(x,y),isoY(x,y,z1)],[isoX(x+w,y),isoY(x+w,y,z1)],
      [isoX(x+w,y+d),isoY(x+w,y+d,z1)],[isoX(x,y+d),isoY(x,y+d,z1)]
    ],topC,edge);
  }

  // ── Floor slab
  drawFace([
    [isoX(0,0),isoY(0,0,0)],
    [isoX(totalW,0),isoY(totalW,0,0)],
    [isoX(totalW,floorD),isoY(totalW,floorD,0)],
    [isoX(0,floorD),isoY(0,floorD,0)]
  ],'#e2e8f0');

  // ── Floor grid (every 5m)
  ctx.strokeStyle='rgba(148,163,184,0.35)';ctx.lineWidth=0.5;ctx.setLineDash([]);
  for(let gx=0;gx<=totalW;gx+=5){
    ctx.beginPath();ctx.moveTo(isoX(gx,0),isoY(gx,0,0));ctx.lineTo(isoX(gx,floorD),isoY(gx,floorD,0));ctx.stroke();
  }
  for(let gy=0;gy<=floorD;gy+=5){
    ctx.beginPath();ctx.moveTo(isoX(0,gy),isoY(0,gy,0));ctx.lineTo(isoX(totalW,gy),isoY(totalW,gy,0));ctx.stroke();
  }
  // Fine grid (every 1m) — lighter
  ctx.strokeStyle='rgba(148,163,184,0.12)';ctx.lineWidth=0.3;
  for(let gx=0;gx<=totalW;gx+=1){
    if(gx%5===0) continue;
    ctx.beginPath();ctx.moveTo(isoX(gx,0),isoY(gx,0,0));ctx.lineTo(isoX(gx,floorD),isoY(gx,floorD,0));ctx.stroke();
  }
  for(let gy=0;gy<=floorD;gy+=1){
    if(gy%5===0) continue;
    ctx.beginPath();ctx.moveTo(isoX(0,gy),isoY(0,gy,0));ctx.lineTo(isoX(totalW,gy),isoY(totalW,gy,0));ctx.stroke();
  }

  // ── Grid distance labels along edges
  ctx.font=`600 ${Math.max(8,isoSc*0.35)}px Segoe UI`;
  ctx.fillStyle='#64748b';ctx.textAlign='center';ctx.textBaseline='top';
  for(let gx=0;gx<=totalW;gx+=5){
    ctx.fillText(gx+'m',isoX(gx,floorD),isoY(gx,floorD,0)+3);
  }
  ctx.textAlign='right';ctx.textBaseline='middle';
  for(let gy=0;gy<=floorD;gy+=5){
    ctx.fillText(gy+'m',isoX(0,gy)-4,isoY(0,gy,0));
  }

  // ── Corridor highlight
  ctx.globalAlpha=0.25;
  drawFace([
    [isoX(corrL,0),isoY(corrL,0,0.02)],
    [isoX(corrR,0),isoY(corrR,0,0.02)],
    [isoX(corrR,totalH),isoY(corrR,totalH,0.02)],
    [isoX(corrL,totalH),isoY(corrL,totalH,0.02)]
  ],'#fbbf24');
  ctx.globalAlpha=1;

  // ── Items — sort back to front (painter's algorithm based on orbit angle)
  const sortedItems=[...items].filter(it=>pos[it.id]).sort((a,b)=>{
    const pa=pos[a.id], pb=pos[b.id];
    // Depth = how far "into" the screen based on orbit angle
    const da=pa.x*sinA+pa.y*cosA;
    const db=pb.x*sinA+pb.y*cosA;
    return da-db;
  });

  let _3dClickZones=[];
  for(const it of sortedItems){
    const p=pos[it.id]; if(!p)continue;
    const{dW,dH,effStack,cols,rows}=getDD(it);
    const stackHeight=it.H*effStack;
    const onL=layout.leftItems.has(it.id);
    const isSel=selId&&it.id===selId;
    const base=isSel?'#eab308':(it.is_long?(onL?'#3b82f6':'#0d9488'):(onL?'#60a5fa':'#34d399'));
    // Draw entire item as ONE solid 3D block (clean, no wireframe grid)
    const topC=shadeColor(base,22);
    const frontC=shadeColor(base,-10);
    const sideC=shadeColor(base,-30);
    drawBox(p.x,p.y,dW,dH,stackHeight,topC,frontC,sideC,0);

    // Optional subtle internal lines to show bundle grid (very light)
    ctx.save();
    ctx.globalAlpha=0.15;ctx.strokeStyle='rgba(0,0,0,0.6)';ctx.lineWidth=0.5;
    // Horizontal stack lines
    for(let s=1;s<effStack;s++){
      const zL=s*it.H;
      // Front or back edge line
      if(showFront){
        ctx.beginPath();
        ctx.moveTo(isoX(p.x,p.y+dH),isoY(p.x,p.y+dH,zL));
        ctx.lineTo(isoX(p.x+dW,p.y+dH),isoY(p.x+dW,p.y+dH,zL));
        ctx.stroke();
      }
      if(showRight){
        ctx.beginPath();
        ctx.moveTo(isoX(p.x+dW,p.y),isoY(p.x+dW,p.y,zL));
        ctx.lineTo(isoX(p.x+dW,p.y+dH),isoY(p.x+dW,p.y+dH,zL));
        ctx.stroke();
      }
      if(showBack){
        ctx.beginPath();
        ctx.moveTo(isoX(p.x,p.y),isoY(p.x,p.y,zL));
        ctx.lineTo(isoX(p.x+dW,p.y),isoY(p.x+dW,p.y,zL));
        ctx.stroke();
      }
      if(showLeft){
        ctx.beginPath();
        ctx.moveTo(isoX(p.x,p.y),isoY(p.x,p.y,zL));
        ctx.lineTo(isoX(p.x,p.y+dH),isoY(p.x,p.y+dH,zL));
        ctx.stroke();
      }
    }
    // Vertical column lines on visible faces
    if(cols>1){
      for(let c=1;c<cols;c++){
        const cx=p.x+c*it.W;
        if(showFront){
          ctx.beginPath();
          ctx.moveTo(isoX(cx,p.y+dH),isoY(cx,p.y+dH,0));
          ctx.lineTo(isoX(cx,p.y+dH),isoY(cx,p.y+dH,stackHeight));
          ctx.stroke();
        }
        if(showBack){
          ctx.beginPath();
          ctx.moveTo(isoX(cx,p.y),isoY(cx,p.y,0));
          ctx.lineTo(isoX(cx,p.y),isoY(cx,p.y,stackHeight));
          ctx.stroke();
        }
      }
    }
    if(rows>1){
      for(let r=1;r<rows;r++){
        const ry=p.y+r*it.L;
        if(showRight){
          ctx.beginPath();
          ctx.moveTo(isoX(p.x+dW,ry),isoY(p.x+dW,ry,0));
          ctx.lineTo(isoX(p.x+dW,ry),isoY(p.x+dW,ry,stackHeight));
          ctx.stroke();
        }
        if(showLeft){
          ctx.beginPath();
          ctx.moveTo(isoX(p.x,ry),isoY(p.x,ry,0));
          ctx.lineTo(isoX(p.x,ry),isoY(p.x,ry,stackHeight));
          ctx.stroke();
        }
      }
    }
    ctx.restore();

    // Record screen-space bounding box for click detection
    const corners3d=[[p.x,p.y,stackHeight],[p.x+dW,p.y,stackHeight],[p.x+dW,p.y+dH,stackHeight],[p.x,p.y+dH,stackHeight],
                     [p.x,p.y,0],[p.x+dW,p.y,0],[p.x+dW,p.y+dH,0],[p.x,p.y+dH,0]];
    let minSX=Infinity,maxSX=-Infinity,minSY=Infinity,maxSY=-Infinity;
    for(const[cx,cy,cz]of corners3d){
      const sx=isoX(cx,cy),sy=isoY(cx,cy,cz);
      minSX=Math.min(minSX,sx);maxSX=Math.max(maxSX,sx);
      minSY=Math.min(minSY,sy);maxSY=Math.max(maxSY,sy);
    }
    _3dClickZones.push({x:minSX,y:minSY,w:maxSX-minSX,h:maxSY-minSY,id:it.id});

    // Label on top — dark with white outline for readability
    const lcx=isoX(p.x+dW/2,p.y+dH/2);
    const lcy=isoY(p.x+dW/2,p.y+dH/2,stackHeight);
    const lfs=Math.max(7,Math.min(10,isoSc*0.35));
    ctx.font=`700 ${lfs}px Segoe UI`;
    ctx.textAlign='center';ctx.textBaseline='bottom';
    const name=shortName(it.item);
    const lbl=name.length>12?name.slice(0,11)+'…':name;
    // Text outline for contrast
    ctx.strokeStyle=isSel?'rgba(180,83,9,0.8)':'rgba(0,0,0,0.6)';ctx.lineWidth=2.5;
    ctx.strokeText(lbl,lcx,lcy-2);
    ctx.fillStyle=isSel?'#fef9c3':'#ffffff';
    ctx.fillText(lbl,lcx,lcy-2);
    // Stack height sub-label
    const hLbl=stackHeight.toFixed(1)+'m';
    ctx.font=`500 ${lfs*0.75}px Segoe UI`;
    ctx.strokeStyle='rgba(0,0,0,0.5)';ctx.lineWidth=2;
    ctx.strokeText(hLbl,lcx,lcy-2+lfs*0.9);
    ctx.fillStyle='#e2e8f0';
    ctx.fillText(hLbl,lcx,lcy-2+lfs*0.9);
  }
  window._3dClickZones=_3dClickZones;

  // ── Title + info
  ctx.font='bold 13px Segoe UI';ctx.fillStyle='#1e293b';
  ctx.textAlign='left';ctx.textBaseline='top';
  ctx.fillText('OMEGA Warehouse — 3D Isometric View',12,10);
  ctx.font='11px Segoe UI';ctx.fillStyle='#64748b';
  ctx.fillText(`${totalW.toFixed(1)} × ${totalH.toFixed(1)} m  ·  Grid: 5m`,12,28);

  ctx.restore();
}

function shadeColor(hex,percent){
  let r=parseInt(hex.slice(1,3),16);
  let g=parseInt(hex.slice(3,5),16);
  let b=parseInt(hex.slice(5,7),16);
  r=Math.max(0,Math.min(255,r+Math.round(r*percent/100)));
  g=Math.max(0,Math.min(255,g+Math.round(g*percent/100)));
  b=Math.max(0,Math.min(255,b+Math.round(b*percent/100)));
  return '#'+[r,g,b].map(c=>c.toString(16).padStart(2,'0')).join('');
}

// ══════════════════════ FOOTPRINT GRAPH VIEW ══════════════════════
function drawFootprintGraph(){
  const W=cvsW, H=cvsH;
  ctx.clearRect(0,0,W,H);
  ctx.fillStyle='#f8fafc';ctx.fillRect(0,0,W,H);
  if(!items.length) return;

  // Calculate area based on fpStackMode
  const sorted=[...items].map(it=>{
    const{dW,dH,fp,effStack,cols,rows}=getDD(it);
    const rawFP=it.L*it.W*it.bundles;
    let modeArea=dW*dH; // default: fpStackMode===1 (current stacked)

    if(fpStackMode===0){
      // No stack: each bundle takes its own floor spot
      modeArea=it.L*it.W*it.bundles;
    } else if(fpStackMode===2){
      // Max stack: use full stack limit (ignoring forklift height)
      const maxStackFloorPos=Math.ceil(it.bundles/it.stack);
      modeArea=it.L*it.W*maxStackFloorPos;
    }

    return{...it, area:modeArea, dW, dH, sH:stackH(it), fp, effStack, cols, rows, rawFP};
  }).sort((a,b)=>b.area-a.area);

  const totalArea=sorted.reduce((s,it)=>s+it.area,0);
  const totalRawFP=sorted.reduce((s,it)=>s+it.rawFP,0);
  const nLong=sorted.filter(i=>i.is_long).length;
  const nBox=sorted.filter(i=>!i.is_long).length;
  const totalBdl=sorted.reduce((s,it)=>s+it.bundles,0);
  const stackSaving=totalRawFP>0?((1-totalArea/totalRawFP)*100).toFixed(0):0;

  // Title
  ctx.font='bold 15px Segoe UI';ctx.fillStyle='#1e293b';
  ctx.textAlign='center';ctx.textBaseline='top';
  ctx.fillText('Material Footprint Analysis',W/2,10);

  // Stack mode buttons
  const btnY=46;
  const btnW=130, btnH=20, btnGap=10;
  const btnLabels=['No Stack (1×)','Stacked (current)'];
  let btnX=W/2-((btnW*2+btnGap)/2);

  for(let i=0;i<2;i++){
    const isActive=fpStackMode===i;
    const bx=btnX+i*(btnW+btnGap);
    ctx.fillStyle=isActive?'#1e3a5f':'#e2e8f0';
    ctx.fillRect(bx, btnY, btnW, btnH);
    ctx.strokeStyle=isActive?'#0f172a':'#cbd5e1';
    ctx.lineWidth=2;
    ctx.strokeRect(bx, btnY, btnW, btnH);
    ctx.font=isActive?'bold 9px Segoe UI':'9px Segoe UI';
    ctx.fillStyle=isActive?'#fff':'#475569';
    ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillText(btnLabels[i], bx+btnW/2, btnY+btnH/2);
  }

  ctx.font='11px Segoe UI';ctx.fillStyle='#64748b';ctx.textAlign='center';
  const modeText=fpStackMode===0?'(no stacking applied)':(fpStackMode===2?'(maximum stacking)':`(${stackSaving}% saved)`);
  ctx.fillText(`${sorted.length} items · ${totalBdl} bundles · ${totalArea.toFixed(1)} m² footprint ${modeText}`,W/2,30);

  // Layout: treemap on left (60%), table on right (40%)
  const tmX=15, tmY=75, tmW=W*0.58-20, tmH=H-123;
  const tbX=W*0.58+5, tbY=75, tbW=W*0.42-20, tbH=H-123;

  // ── TREEMAP ──
  ctx.strokeStyle='#cbd5e1';ctx.lineWidth=1;
  ctx.strokeRect(tmX,tmY,tmW,tmH);

  // Squarified treemap layout
  function treemapLayout(items, x, y, w, h){
    if(!items.length) return [];
    if(items.length===1){
      return [{item:items[0], x, y, w, h}];
    }
    const total=items.reduce((s,it)=>s+it.area,0);
    if(total<=0) return [];
    const rects=[];
    let remaining=[...items];
    let cx=x, cy=y, cw=w, ch=h;

    while(remaining.length>0){
      const isWide=cw>=ch;
      const side=isWide?ch:cw;
      let row=[], rowArea=0;
      const remArea=remaining.reduce((s,it)=>s+it.area,0);

      for(let i=0;i<remaining.length;i++){
        const testRow=[...row, remaining[i]];
        const testArea=rowArea+remaining[i].area;
        const rowLen=testArea/remArea*(isWide?cw:ch);
        // Check worst aspect ratio
        let worstAR=0;
        for(const it of testRow){
          const itLen=it.area/testArea*side;
          const ar=Math.max(rowLen/itLen, itLen/rowLen);
          worstAR=Math.max(worstAR,ar);
        }
        if(row.length>0){
          let prevWorst=0;
          const prevArea=rowArea;
          const prevLen=prevArea/remArea*(isWide?cw:ch);
          for(const it of row){
            const itLen=it.area/prevArea*side;
            const ar=Math.max(prevLen/itLen, itLen/prevLen);
            prevWorst=Math.max(prevWorst,ar);
          }
          if(worstAR>prevWorst && row.length>0) break;
        }
        row.push(remaining[i]);
        rowArea+=remaining[i].area;
      }

      // Position row items
      const rowFrac=rowArea/remArea;
      const rowLen=isWide?cw*rowFrac:ch*rowFrac;
      let offset=0;
      for(const it of row){
        const frac=it.area/rowArea;
        const itLen=side*frac;
        if(isWide){
          rects.push({item:it, x:cx, y:cy+offset, w:rowLen, h:itLen});
        } else {
          rects.push({item:it, x:cx+offset, y:cy, w:itLen, h:rowLen});
        }
        offset+=itLen;
      }

      // Shrink remaining area
      if(isWide){cx+=rowLen;cw-=rowLen;}
      else{cy+=rowLen;ch-=rowLen;}
      remaining=remaining.slice(row.length);
    }
    return rects;
  }

  const rects=treemapLayout(sorted, tmX, tmY, tmW, tmH);
  _fpClickZones=[];
  for(const r of rects){
    const it=r.item;
    _fpClickZones.push({x:r.x,y:r.y,w:r.w,h:r.h,item:it.item});
    const isSel=selId&&items.find(i=>i.id===selId&&i.item===it.item);
    const base=isSel?'#eab308':(it.is_long?'#3b82f6':'#22c55e');
    // Intensity by area proportion
    const intensity=isSel?1:Math.min(1, it.area/sorted[0].area*0.6+0.4);
    ctx.globalAlpha=intensity;
    ctx.fillStyle=base;
    ctx.fillRect(r.x+1, r.y+1, r.w-2, r.h-2);
    ctx.globalAlpha=1;
    ctx.strokeStyle=isSel?'#b45309':(it.is_long?'#1d4ed8':'#15803d');
    ctx.lineWidth=isSel?2.5:1;
    ctx.strokeRect(r.x+1, r.y+1, r.w-2, r.h-2);

    // Label if big enough
    if(r.w>40 && r.h>22){
      const fs=Math.min(11, r.w*0.12, r.h*0.28);
      ctx.font=`700 ${fs}px Segoe UI`;
      ctx.fillStyle='#fff';ctx.textAlign='center';ctx.textBaseline='middle';
      const name=it.item.length>Math.floor(r.w/(fs*0.55))?it.item.slice(0,Math.floor(r.w/(fs*0.55))-1)+'…':it.item;
      ctx.fillText(name, r.x+r.w/2, r.y+r.h/2-fs*0.4);
      // Sub info
      ctx.font=`500 ${fs*0.7}px Segoe UI`;
      ctx.fillStyle='rgba(255,255,255,0.85)';
      ctx.fillText(`${it.area.toFixed(1)}m² · ×${it.bundles} · stk${it.effStack}`, r.x+r.w/2, r.y+r.h/2+fs*0.5);
    } else if(r.w>20 && r.h>14){
      const fs=Math.min(8, r.w*0.15, r.h*0.4);
      ctx.font=`600 ${fs}px Segoe UI`;
      ctx.fillStyle='#fff';ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.fillText(it.area.toFixed(1), r.x+r.w/2, r.y+r.h/2);
    }
  }

  // ── TABLE (right side) ──
  ctx.fillStyle='#fff';ctx.fillRect(tbX, tbY, tbW, tbH);
  ctx.strokeStyle='#e2e8f0';ctx.lineWidth=1;
  ctx.strokeRect(tbX, tbY, tbW, tbH);

  // Table header
  const rowH=18;
  ctx.fillStyle='#1e3a5f';ctx.fillRect(tbX, tbY, tbW, rowH+2);
  ctx.font='bold 9px Segoe UI';ctx.fillStyle='#fff';ctx.textBaseline='middle';
  const cols=[{l:'#',w:16},{l:'Material',w:tbW*0.28},{l:'L×W',w:48},{l:'Bdl',w:24},{l:'Stk',w:22},{l:'H(m)',w:28},{l:'Floor',w:28},{l:'Area m²',w:42},{l:'%',w:26}];
  let colX=tbX+4;
  for(const c of cols){
    ctx.textAlign=c.l==='Material'?'left':'center';
    ctx.fillText(c.l, c.l==='Material'?colX:colX+c.w/2, tbY+rowH/2+1);
    colX+=c.w;
  }

  // Table rows — scrollable
  const visibleRows=Math.floor((tbH-rowH-30)/rowH);
  const totalContentH=sorted.length*rowH;
  const maxScroll=Math.max(0, totalContentH-(visibleRows*rowH));
  fpScrollY=Math.max(0, Math.min(fpScrollY, maxScroll));
  const startRow=Math.floor(fpScrollY/rowH);
  const offsetY=fpScrollY%rowH;

  ctx.save();
  ctx.beginPath();
  ctx.rect(tbX, tbY+rowH+2, tbW, visibleRows*rowH);
  ctx.clip();

  for(let vi=0;vi<=visibleRows+1;vi++){
    const i=startRow+vi;
    if(i>=sorted.length) break;
    const it=sorted[i];
    const ry=tbY+rowH+2+vi*rowH-offsetY;
    if(ry<tbY+rowH||ry>tbY+tbH) continue;
    const isRowSel=selId&&items.find(ii=>ii.id===selId&&ii.item===it.item);
    ctx.fillStyle=isRowSel?'#fef9c3':(i%2?'#f8fafc':'#fff');
    ctx.fillRect(tbX, ry, tbW, rowH);
    if(isRowSel){ctx.strokeStyle='#eab308';ctx.lineWidth=1;ctx.strokeRect(tbX,ry,tbW,rowH);}
    // Also record as click zone for table row
    _fpClickZones.push({x:tbX,y:ry,w:tbW,h:rowH,item:it.item});
    ctx.font='9px Segoe UI';ctx.fillStyle='#1e293b';ctx.textBaseline='middle';
    colX=tbX+4;
    const maxChars=Math.max(10,Math.floor(cols[1].w/(4.5)));
    const vals=[
      {v:`${i+1}`, a:'center'},
      {v:it.item.length>maxChars?it.item.slice(0,maxChars-1)+'…':it.item, a:'left'},
      {v:`${it.dW.toFixed(1)}×${it.dH.toFixed(1)}`, a:'center'},
      {v:`${it.bundles}`, a:'center'},
      {v:`×${it.effStack}`, a:'center'},
      {v:it.sH.toFixed(1), a:'center'},
      {v:`${it.fp}`, a:'center'},
      {v:it.area.toFixed(1), a:'center'},
      {v:(it.area/totalArea*100).toFixed(0)+'%', a:'center'}
    ];
    for(let j=0;j<cols.length;j++){
      ctx.textAlign=vals[j].a;
      ctx.font=j===1?'600 9px Segoe UI':'9px Segoe UI';
      ctx.fillStyle=j===0?'#94a3b8':'#1e293b';
      const tx=vals[j].a==='left'?colX:colX+cols[j].w/2;
      ctx.fillText(vals[j].v, tx, ry+rowH/2);
      colX+=cols[j].w;
    }
    // Type dot
    ctx.fillStyle=it.is_long?'#3b82f6':'#22c55e';
    ctx.beginPath();ctx.arc(tbX+10, ry+rowH/2, 3, 0, Math.PI*2);ctx.fill();
  }
  ctx.restore();

  // Scrollbar
  if(sorted.length>visibleRows){
    const sbX=tbX+tbW-8, sbY=tbY+rowH+4, sbH=visibleRows*rowH-4;
    ctx.fillStyle='rgba(0,0,0,0.08)';
    ctx.fillRect(sbX,sbY,6,sbH);
    const thumbH=Math.max(20, sbH*(visibleRows/sorted.length));
    const thumbY=maxScroll>0?sbY+(fpScrollY/maxScroll)*(sbH-thumbH):sbY;
    ctx.fillStyle='rgba(30,58,95,0.35)';
    ctx.fillRect(sbX,thumbY,6,thumbH);
    // Item count
    ctx.font='italic 8px Segoe UI';ctx.fillStyle='#94a3b8';ctx.textAlign='right';ctx.textBaseline='top';
    ctx.fillText(`${startRow+1}-${Math.min(startRow+visibleRows,sorted.length)} of ${sorted.length}`,tbX+tbW-12, tbY+rowH+2+visibleRows*rowH+2);
  }

  // Summary bar at bottom
  const sy=H-38;
  ctx.fillStyle='#1e3a5f';ctx.fillRect(15,sy,W-30,30);
  ctx.font='bold 11px Segoe UI';ctx.fillStyle='#fff';
  ctx.textAlign='left';ctx.textBaseline='middle';
  ctx.fillText(`STACKED: ${totalArea.toFixed(1)} m²  ·  Raw: ${totalRawFP.toFixed(0)} m²  ·  Saved ${stackSaving}% by stacking  ·  ${totalBdl} bundles`,25,sy+15);
  ctx.textAlign='right';
  ctx.fillText(`${nLong} long + ${nBox} box  ·  Largest: ${sorted[0].item}`,W-25,sy+15);
}

// ══════════════════════ BUNDLE & S/N VERIFICATION VIEW ══════════════════════
function drawBundleDetail(){
  const W=cvsW, H=cvsH;
  ctx.clearRect(0,0,W,H);
  ctx.fillStyle='#f8fafc';ctx.fillRect(0,0,W,H);
  _bdClickZones=[];

  // ── Gather raw source data (per container, not consolidated) ──
  const sv=document.getElementById('shipSel').value;
  const cv=document.getElementById('contSel').value;

  // Build structured data: containers → items → bundles
  let containers=[];  // [{id, ship, items:[{item,L,W,H,stack,is_long,bundles,sns,match}]}]
  function addCont(shipId, c){
    const cData={id:c.id, ship:shipId, project:c.project||'', items:[]};
    c.items.forEach(it=>{
      const sns=it.sns||[];
      cData.items.push({
        item:it.item, L:it.L, W:it.W, H:it.H, stack:it.stack,
        is_long:it.is_long, bundles:it.bundles, sns:sns,
        sn_contents:it.sn_contents||null,
        match:sns.length===it.bundles
      });
    });
    containers.push(cData);
  }
  let scopeLabel='';
  if(sc==='container'){
    const si=sv!==''?+sv:0, ci=cv!==''?+cv:0;
    const s=ships[si]; if(!s) return;
    const c=s.containers[ci]; if(!c) return;
    scopeLabel=`Ship ${s.id}  ›  ${c.id}`;
    addCont(s.id, c);
  } else if(sc==='shipment'){
    const si=sv!==''?+sv:0;
    const s=ships[si]; if(!s) return;
    scopeLabel=`Ship ${s.id}  ›  ${s.containers.length} Containers`;
    s.containers.forEach(c=>addCont(s.id, c));
  } else {
    scopeLabel='All Shipments';
    ships.forEach(s=>s.containers.forEach(c=>addCont(s.id, c)));
  }

  // ── Stats ──
  let totalBdl=0, totalSN=0, allMatch=true;
  const snSet=new Set();
  containers.forEach(c=>c.items.forEach(it=>{
    totalBdl+=it.bundles; totalSN+=it.sns.length;
    if(!it.match) allMatch=false;
    it.sns.forEach(sn=>snSet.add(c.ship+'_'+sn));
  }));
  const uniqueParts=new Set(containers.flatMap(c=>c.items.map(i=>i.item))).size;

  // ── Pre-calculate layout (boxes for each container section) ──
  const pad=14, boxW=62, boxH=52, boxGap=4;
  const contHdrH=28, itemHdrH=20, itemPadBot=8;
  const maxBoxCols=Math.floor((W-pad*2)/(boxW+boxGap));

  // Calculate total height needed
  let totalContentH=10;
  containers.forEach(c=>{
    totalContentH+=contHdrH;
    c.items.forEach(it=>{
      // Check if item has GB/T spec — taller header
      let hasGB=false;
      if(it.sn_contents){
        const fk=Object.keys(it.sn_contents)[0];
        if(fk){const fc=it.sn_contents[fk][0];if(fc&&fc.dim&&/^GB\/T/.test(fc.dim)) hasGB=true;}
      }
      totalContentH+=hasGB?itemHdrH+10:itemHdrH;
      const rows_=Math.ceil(it.bundles/maxBoxCols);
      totalContentH+=rows_*(boxH+boxGap)+itemPadBot;
    });
    totalContentH+=10;
  });

  // ── Title Bar ──
  const titleH=50;
  ctx.fillStyle='#1e293b';ctx.font='bold 15px Segoe UI';ctx.textAlign='left';ctx.textBaseline='top';
  ctx.fillText('Bundle & S/N Verification',16,8);
  ctx.font='11px Segoe UI';ctx.fillStyle='#64748b';
  ctx.fillText(scopeLabel,260,11);

  // Status badge
  const bY=30;
  ctx.fillStyle=allMatch?'#16a34a':'#dc2626';
  roundRect(ctx,16,bY,allMatch?110:130,16,3);ctx.fill();
  ctx.fillStyle='#fff';ctx.font='bold 9px Segoe UI';ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText(allMatch?'ALL VERIFIED':'MISMATCH',16+(allMatch?55:65),bY+8);
  ctx.textAlign='left';ctx.font='10px Segoe UI';ctx.fillStyle='#475569';
  ctx.fillText(`${totalBdl} bundles  ·  ${uniqueParts} parts  ·  ${containers.length} containers  ·  ${snSet.size} S/N`,allMatch?136:156,bY+2);

  // ── Content Area with scroll ──
  const contentTop=titleH;
  const contentH=H-contentTop-22;
  const maxScroll=Math.max(0,totalContentH-contentH);
  bdScrollY=Math.max(0,Math.min(bdScrollY,maxScroll));

  ctx.save();
  ctx.beginPath();ctx.rect(0,contentTop,W,contentH);ctx.clip();

  let cy=contentTop+8-bdScrollY;
  const palette=['#3b82f6','#0d9488','#8b5cf6','#e11d48','#ea580c','#16a34a','#0284c7','#7c3aed'];

  for(let ci=0;ci<containers.length;ci++){
    const c=containers[ci];
    const contColor=palette[ci%palette.length];

    // ── Container Header ──
    if(cy+contHdrH>contentTop-50 && cy<H+50){
      ctx.fillStyle=contColor;ctx.fillRect(pad,cy,W-pad*2,contHdrH);
      // Small triangle
      ctx.fillStyle='rgba(255,255,255,0.15)';
      ctx.beginPath();ctx.moveTo(W-pad,cy);ctx.lineTo(W-pad-contHdrH,cy);ctx.lineTo(W-pad,cy+contHdrH);ctx.fill();
      ctx.fillStyle='#fff';ctx.font='bold 11px Segoe UI';ctx.textAlign='left';ctx.textBaseline='middle';
      ctx.fillText(`Ship ${c.ship}  ›  ${c.id}`,pad+10,cy+contHdrH/2);
      // Right side: totals
      const cBdl=c.items.reduce((s,it)=>s+it.bundles,0);
      const cSN=c.items.reduce((s,it)=>s+it.sns.length,0);
      const cOK=c.items.every(it=>it.match);
      ctx.textAlign='right';ctx.font='10px Segoe UI';
      ctx.fillText(`${cBdl} bdl  ·  ${cSN} S/N  ·  ${cOK?'✓ OK':'✗ FAIL'}`,W-pad-8,cy+contHdrH/2);
      ctx.textAlign='left';
    }
    cy+=contHdrH;

    // ── Items in this container ──
    for(const it of c.items){
      // Check if this item is selected from sidebar
      const isBDSel=selId&&items.find(i=>i.id===selId&&i.item===it.item);

      // Item header row — show GB/T spec if available
      // Derive GB/T label from sn_contents
      let gbLabel='';
      let gbSub='';
      if(it.sn_contents){
        const firstSN=Object.keys(it.sn_contents)[0];
        if(firstSN){
          const fc=it.sn_contents[firstSN][0];
          if(fc&&fc.dim&&(/^[GC]B\/T/.test(fc.dim)||/^Q\//.test(fc.dim))){
            gbLabel=fc.dim;
            gbSub='('+it.item+')';
          }
        }
      }
      const itemHdrActualH=gbLabel?itemHdrH+10:itemHdrH;
      if(cy+itemHdrActualH>contentTop-30 && cy<H+30){
        ctx.fillStyle=isBDSel?'#eff6ff':'#f1f5f9';ctx.fillRect(pad,cy,W-pad*2,itemHdrActualH);
        if(isBDSel){ctx.strokeStyle='#2563eb';ctx.lineWidth=1.5;ctx.strokeRect(pad,cy,W-pad*2,itemHdrActualH);}
        ctx.fillStyle=isBDSel?'#2563eb':contColor;ctx.fillRect(pad,cy,3,itemHdrActualH);
        if(gbLabel){
          // Two-line header: GB/T spec on top, (item name) below
          ctx.font='bold 9.5px Segoe UI';ctx.fillStyle='#1e293b';ctx.textBaseline='top';
          ctx.fillText(gbLabel,pad+10,cy+3);
          ctx.font='8.5px Segoe UI';ctx.fillStyle='#64748b';
          ctx.fillText(gbSub,pad+10,cy+16);
        } else {
          ctx.font='bold 9px Segoe UI';ctx.fillStyle='#1e293b';ctx.textBaseline='middle';
          const label=it.item.length>35?it.item.slice(0,33)+'…':it.item;
          ctx.fillText(label,pad+10,cy+itemHdrActualH/2);
        }
        // Type badge
        const typeBg=it.is_long?'#dbeafe':'#dcfce7';
        const typeFg=it.is_long?'#1e40af':'#166534';
        const typeL=it.is_long?'LONG':'BOX';
        const labelW=gbLabel?ctx.measureText(gbLabel).width:ctx.measureText(it.item.length>35?it.item.slice(0,33)+'…':it.item).width;
        const tx=pad+10+labelW+8;
        ctx.fillStyle=typeBg;ctx.fillRect(tx,cy+3,36,14);
        ctx.fillStyle=typeFg;ctx.font='bold 7px Segoe UI';ctx.textAlign='center';ctx.textBaseline='middle';
        ctx.fillText(typeL,tx+18,cy+10);ctx.textAlign='left';
        // Dims + count on right
        ctx.font='9px Segoe UI';ctx.fillStyle='#64748b';ctx.textAlign='right';ctx.textBaseline='middle';
        ctx.fillText(`${it.L}×${it.W}×${it.H}m  ·  stk×${it.stack}  ·  ${it.bundles} bdl  ·  ${it.sns.length} S/N`,W-pad-8,cy+itemHdrActualH/2);
        ctx.textAlign='left';
        // Match indicator
        if(!it.match){
          ctx.fillStyle='#dc2626';ctx.font='bold 8px Segoe UI';
          ctx.fillText(`MISMATCH: ${it.bundles} bdl ≠ ${it.sns.length} S/N`,pad+10,cy+itemHdrActualH-2);
        }
      }
      cy+=itemHdrActualH;

      // ── Bundle Boxes ──
      const bRows=Math.ceil(it.bundles/maxBoxCols);
      for(let bi=0;bi<it.bundles;bi++){
        const bCol=bi%maxBoxCols;
        const bRow=Math.floor(bi/maxBoxCols);
        const bx=pad+bCol*(boxW+boxGap);
        const by=cy+bRow*(boxH+boxGap);

        if(by+boxH<contentTop-10||by>H+10) continue;

        const sn=bi<it.sns.length?it.sns[bi]:null;
        const ok=sn!==null;
        const isActive=bdPopup&&bdPopup.sn===sn&&bdPopup.cont===c.id&&bdPopup.item===it.item;

        // Box shadow
        ctx.fillStyle=(isActive||isBDSel)?'rgba(59,130,246,0.25)':'rgba(0,0,0,0.06)';
        ctx.fillRect(bx+1,by+1,boxW,boxH);

        // Box fill
        ctx.fillStyle=isActive?'#eff6ff':(isBDSel?(ok?'#eff6ff':'#fef2f2'):(ok?'#fff':'#fef2f2'));
        ctx.fillRect(bx,by,boxW,boxH);

        // Box border
        ctx.strokeStyle=isActive?'#2563eb':(isBDSel?'#3b82f6':(ok?contColor:'#dc2626'));
        ctx.lineWidth=(isActive||isBDSel)?2.5:(ok?1.2:2);
        ctx.strokeRect(bx,by,boxW,boxH);

        // Top color stripe
        ctx.fillStyle=isActive?'#2563eb':(isBDSel?'#3b82f6':(ok?contColor:'#dc2626'));
        ctx.fillRect(bx,by,boxW,3);

        // Short item name at top
        ctx.font='600 6.5px Segoe UI';ctx.textAlign='center';ctx.textBaseline='top';
        ctx.fillStyle='#64748b';
        const sName=shortName(it.item);
        const sLabel=sName.length>9?sName.slice(0,8)+'…':sName;
        ctx.fillText(sLabel,bx+boxW/2,by+5);

        // S/N number — big and centered
        ctx.font='bold 14px Segoe UI';ctx.textAlign='center';ctx.textBaseline='middle';
        ctx.fillStyle=ok?'#1e293b':'#dc2626';
        ctx.fillText(ok?''+sn:'—',bx+boxW/2,by+boxH/2+2);

        // Bundle index below S/N
        ctx.font='7px Segoe UI';ctx.fillStyle='#94a3b8';
        ctx.fillText(`${bi+1}/${it.bundles}`,bx+boxW/2,by+boxH-7);

        // Checkmark or X in top-right corner
        ctx.font='bold 8px Segoe UI';
        ctx.fillStyle=ok?'#16a34a':'#dc2626';
        ctx.textAlign='right';
        ctx.fillText(ok?'✓':'✗',bx+boxW-3,by+10);
        ctx.textAlign='left';

        // Multi-item S/N badge (bottom-left) — shows how many items inside THIS bundle
        const snKey=sn!==null?''+sn:null;
        const snContents=snKey&&it.sn_contents?it.sn_contents[snKey]:null;
        const nContents=snContents?snContents.length:1;
        if(nContents>1){
          ctx.fillStyle='#fbbf24';
          ctx.fillRect(bx+1,by+boxH-10,14,9);
          ctx.fillStyle='#78350f';ctx.font='bold 6px Segoe UI';ctx.textAlign='center';ctx.textBaseline='middle';
          ctx.fillText(nContents+'x',bx+8,by+boxH-5.5);
          ctx.textAlign='left';ctx.textBaseline='top';
        }

        // Record click zone
        _bdClickZones.push({
          x:bx,y:by,w:boxW,h:boxH,
          sn:sn,item:it.item,cont:c.id,ship:c.ship,
          L:it.L,W:it.W,H:it.H,stack:it.stack,is_long:it.is_long,
          bdlIdx:bi+1,bdlTotal:it.bundles,
          contItems:c.items, contColor:contColor,
          snContents:snContents
        });
      }
      cy+=bRows*(boxH+boxGap)+itemPadBot;
    }
    cy+=10;
  }
  ctx.restore();

  // ── Popup overlay when a box is clicked ──
  if(bdPopup){
    const p=bdPopup;
    const popW=380;
    const sc=p.snContents||[{item:p.item,desc:'',dim:'',qty:''}];
    // Calculate popup height based on contents
    const contentLines=sc.length;
    const popH_=Math.min(H-60, 100+contentLines*44+30);
    // Position popup near click, but keep on screen
    let px=Math.min(p.px||W/2, W-popW-10);
    let py=Math.min(p.py||H/2, H-popH_-30);
    if(px<10) px=10; if(py<titleH) py=titleH;

    // Dim background
    ctx.fillStyle='rgba(0,0,0,0.3)';ctx.fillRect(0,titleH,W,H-titleH);

    // Popup card
    ctx.fillStyle='#fff';
    ctx.shadowColor='rgba(0,0,0,0.2)';ctx.shadowBlur=16;ctx.shadowOffsetX=0;ctx.shadowOffsetY=4;
    ctx.fillRect(px,py,popW,popH_);
    ctx.shadowBlur=0;ctx.shadowOffsetX=0;ctx.shadowOffsetY=0;

    // Top bar with container color
    ctx.fillStyle=p.contColor||'#3b82f6';
    ctx.fillRect(px,py,popW,28);
    ctx.fillStyle='#fff';ctx.font='bold 11px Segoe UI';ctx.textAlign='left';ctx.textBaseline='middle';
    ctx.fillText(`Ship ${p.ship}  ›  ${p.cont}`,px+10,py+14);
    // Close X
    ctx.textAlign='right';ctx.font='bold 14px Segoe UI';
    ctx.fillText('✕',px+popW-8,py+14);
    ctx.textAlign='left';

    // Selected bundle header
    let oy=py+36;
    ctx.fillStyle='#eff6ff';ctx.fillRect(px+6,oy-2,popW-12,22);
    ctx.fillStyle='#1e3a5f';ctx.font='bold 10px Segoe UI';ctx.textBaseline='top';
    ctx.fillText(`S/N ${p.sn}  ·  Bundle ${p.bdlIdx}/${p.bdlTotal}`,px+12,oy+2);
    ctx.fillStyle='#475569';ctx.font='9px Segoe UI';
    ctx.fillText(`${p.L}×${p.W}×${p.H}m · ${p.is_long?'LONG':'BOX'} · stk×${p.stack}`,px+12,oy+14);
    oy+=32;

    // Bundle contents header
    const nItems=sc.length;
    ctx.fillStyle='#64748b';ctx.font='bold 9px Segoe UI';
    ctx.fillText(`📦 Inside this bundle: ${nItems} item${nItems>1?'s':''}`,px+10,oy);
    oy+=16;

    // List each content item with GB/T spec format
    for(let ci=0;ci<sc.length;ci++){
      const c=sc[ci];
      if(oy>py+popH_-30) break;

      // Row background alternating
      if(ci%2===0){ctx.fillStyle='#f8fafc';ctx.fillRect(px+6,oy-2,popW-12,40);}

      // Item number
      ctx.fillStyle='#94a3b8';ctx.font='bold 8px Segoe UI';ctx.textBaseline='top';
      ctx.fillText(`${ci+1}.`,px+10,oy);

      // GB/T spec line (primary) — e.g. "GB/T 70.1-2008 M10×25"
      const dim=c.dim||'';
      const desc=c.desc||'';
      const itemName=c.item||'';
      // Format: GB/T spec (item name) or item name (description)
      let mainLine='';
      let subLine='';
      if(dim&&(/^[GC]B\/T/.test(dim)||/^Q\//.test(dim))){
        // Has standard spec → show spec as main, item name as sub
        mainLine=dim;
        subLine=`(${itemName})`;
      } else if(dim){
        mainLine=itemName;
        subLine=dim;
      } else if(desc){
        mainLine=itemName;
        subLine=`(${desc})`;
      } else {
        mainLine=itemName;
      }
      ctx.fillStyle='#1e293b';ctx.font='bold 9.5px Segoe UI';
      ctx.fillText(mainLine.length>45?mainLine.slice(0,43)+'…':mainLine,px+24,oy);

      // Sub-line: description/name in lighter color
      if(subLine){
        ctx.fillStyle='#64748b';ctx.font='9px Segoe UI';
        ctx.fillText(subLine.length>50?subLine.slice(0,48)+'…':subLine,px+24,oy+13);
      }

      // Qty on right
      if(c.qty){
        ctx.fillStyle='#475569';ctx.font='bold 9px Segoe UI';ctx.textAlign='right';
        ctx.fillText(`×${c.qty}`,px+popW-10,oy+6);
        ctx.textAlign='left';
      }

      oy+=ci%2===0?40:40;
    }

    // Warning banner if multiple items in this bundle
    if(nItems>1){
      oy+=4;
      ctx.fillStyle='#fef3c7';ctx.fillRect(px+6,oy,popW-12,18);
      ctx.fillStyle='#92400e';ctx.font='bold 8px Segoe UI';ctx.textBaseline='middle';
      ctx.fillText(`⚠ ${nItems} different items packed in this S/N bundle`,px+12,oy+9);
      ctx.textBaseline='top';
    }
  }

  // ── Footer ──
  const footY=H-20;
  ctx.fillStyle='#1e3a5f';ctx.fillRect(0,footY,W,20);
  ctx.font='bold 9px Segoe UI';ctx.fillStyle='#fff';ctx.textAlign='left';ctx.textBaseline='middle';
  ctx.fillText(`Total: ${totalBdl} bundles  ·  ${uniqueParts} parts  ·  ${containers.length} containers  ·  ${snSet.size} S/N verified`,10,footY+10);
  ctx.textAlign='right';
  ctx.fillText(allMatch?'DATA INTEGRITY: PASS':'DATA INTEGRITY: FAIL',W-10,footY+10);

  // ── Scrollbar ──
  if(maxScroll>0){
    const sbW=8,sbX=W-12,sbY=contentTop,sbH_=contentH;
    ctx.fillStyle='#e2e8f0';ctx.fillRect(sbX,sbY,sbW,sbH_);
    const thumbH=Math.max(20,sbH_*(contentH/totalContentH));
    const thumbY=sbY+(bdScrollY/maxScroll)*(sbH_-thumbH);
    ctx.fillStyle='#94a3b8';ctx.fillRect(sbX,thumbY,sbW,thumbH);
  }
}

// (S/N Verify merged into drawBundleDetail above)

function roundRect(ctx,x,y,w,h,r){
  ctx.beginPath();ctx.moveTo(x+r,y);ctx.lineTo(x+w-r,y);ctx.quadraticCurveTo(x+w,y,x+w,y+r);
  ctx.lineTo(x+w,y+h-r);ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h);ctx.lineTo(x+r,y+h);
  ctx.quadraticCurveTo(x,y+h,x,y+h-r);ctx.lineTo(x,y+r);ctx.quadraticCurveTo(x,y,x+r,y);ctx.closePath();
}

// ══════════════════════ ANALYSIS REPORT VIEW ══════════════════════
// ── Report lines cache: built once, rendered many times ──
let _rptLines=null, _rptContentH=0, _rptDirty=true;
function invalidateReport(){_rptDirty=true;_rptLines=null;}

function buildReportLines(){
  if(!_rptDirty&&_rptLines) return;

  const totalBdl=items.reduce((s,it)=>s+it.bundles,0);
  const nLong=items.filter(i=>i.is_long).length;
  const nBox=items.filter(i=>!i.is_long).length;
  const rawFP=items.reduce((s,it)=>s+it.L*it.W*it.bundles,0);
  const stackedFP=items.reduce((s,it)=>{const{dW,dH}=getDD(it);return s+dW*dH;},0);
  const totalVol=items.reduce((s,it)=>s+it.L*it.W*it.H*it.bundles,0);
  const maxStkH=items.length?Math.max(...items.map(it=>stackH(it))):0;
  const totalArea=items.reduce((s,it)=>s+it.sqm,0);

  const corrL=layout?layout.corrL:0, corrR=layout?layout.corrR:0;
  const totalW=layout?layout.totalW:0, totalH=layout?layout.totalH:0;
  const lw=corrL-SIDE_M, rw=totalW-corrR-SIDE_M;
  const rentArea=layout?(totalW*totalH):0;
  const utilPct=rentArea>0?(stackedFP/rentArea*100).toFixed(1):'0';

  const trips=getCachedTruckTrips();
  const nTrips=trips.length;
  const avgUtil=nTrips>0?(trips.reduce((s,t)=>{
    const used=t.loads.reduce((a,l)=>a+l.L*l.W,0);
    return s+used/(DECK_L*DECK_W)*100;
  },0)/nTrips).toFixed(0):'0';
  const roundTrip=LOAD_TIME_MIN+DRIVE_TIME_MIN+UNLOAD_TIME_MIN+DRIVE_TIME_MIN;
  const workMins=(WORK_END-WORK_START)*60-LUNCH_MIN-BUFFER_MIN;
  const tripsPerDay=Math.floor(workMins/roundTrip);
  const daysNeeded=nTrips>0?Math.ceil(nTrips/tripsPerDay):0;

  const rc=rptCache||{totalGBpcs:0,totalNonGBpcs:0,totalAllPcs:0,gbPct:0,gbArea:0,structArea:0,gbFamilies:[]};
  const totalGBpcs=rc.totalGBpcs, totalNonGBpcs=rc.totalNonGBpcs;
  const totalAllPcs=rc.totalAllPcs;
  const gbPct=totalAllPcs>0?(totalGBpcs/totalAllPcs*100).toFixed(1):'0';
  const gbArea=rc.gbArea, structArea=rc.structArea;

  const L=[];
  const sec=(t,color)=>L.push({t:'s',text:t,color:color||'#1e3a5f'});
  const kv=(k,v,hl)=>L.push({t:'k',key:k,val:v,hl:hl});
  const gap=()=>L.push({t:'g'});
  const note=(t)=>L.push({t:'n',text:t});
  const tH=(cols)=>L.push({t:'th',cols:cols});
  const tR=(cols,hl)=>L.push({t:'tr',cols:cols,hl:hl});
  const bar=(label,pv,color)=>L.push({t:'b',label:label,pct:pv,color:color||'#3b82f6'});

  sec('OVERVIEW — '+({container:'Container',shipment:'Shipment',all:'All Shipments',multi:'Combined Ships',multiCont:'Combined Containers'}[sc]||sc).toUpperCase());
  kv('Materials', items.length);
  kv('Total bundles', totalBdl.toLocaleString());
  kv('Long parts / Box items', nLong+' / '+nBox);
  kv('Total floor area', totalArea.toFixed(1)+' m²');
  kv('Total volume', totalVol.toFixed(0)+' m³');
  kv('Total pcs (all in bundles)', totalAllPcs.toLocaleString());
  kv('Structural pcs', totalNonGBpcs.toLocaleString()+' ('+(totalAllPcs>0?((totalNonGBpcs/totalAllPcs)*100).toFixed(1):'0')+'%)');
  kv('GB/T fastener pcs', totalGBpcs.toLocaleString()+' ('+gbPct+'%)', totalGBpcs>0?'#fef3c7':null);
  gap();

  if(totalGBpcs>0){
    sec('GB/T vs STRUCTURAL — WHY SEPARATE','#64748b');
    bar('By Pcs: Structural',totalAllPcs>0?(totalNonGBpcs/totalAllPcs*100):0,'#1e3a5f');
    bar('By Pcs: GB/T Fasteners',totalAllPcs>0?(totalGBpcs/totalAllPcs*100):0,'#94a3b8');
    const ta=gbArea+structArea;
    bar('By Area: Structural',ta>0?(structArea/ta*100):0,'#16a34a');
    bar('By Area: GB/T',ta>0?(gbArea/ta*100):0,'#d1d5db');
    kv('GB/T area', gbArea.toFixed(1)+' m² ('+(ta>0?(gbArea/ta*100).toFixed(1):'0')+'%)');
    kv('Structural area', structArea.toFixed(1)+' m² ('+(ta>0?(structArea/ta*100).toFixed(1):'0')+'%)');
    note('GB/T = Chinese fastener standard (bolts, nuts, washers) — tiny pcs, inflate counts');
    gap();
    sec('GB/T FASTENER FAMILIES','#64748b');
    const descMap={'GB/T 5783':'Hex Bolt','GB/T 889.1':'Lock Nut','GB/T 97.1':'Flat Washer','GB/T 70.1':'Socket Screw','GB/T 96.1':'Large Washer','CB/T3818':'Buckle'};
    tH(['Standard','Type','Specs','Pcs','% of GB/T']);
    rc.gbFamilies.forEach(fam=>{
      const sk=fam.std.split('-')[0]||fam.std;
      tR([fam.std,descMap[sk]||sk,String(fam.specs),fam.qty.toLocaleString(),(totalGBpcs>0?(fam.qty/totalGBpcs*100).toFixed(1):'0')+'%']);
    });
    gap();
  }

  sec('TOP MATERIALS BY FLOOR AREA');
  tH(['#','Material','Type','Area m²','% Area','Bundles']);
  [...items].sort((a,b)=>b.sqm-a.sqm).slice(0,20).forEach((it,i)=>{
    const ap=totalArea>0?(it.sqm/totalArea*100).toFixed(1):'0';
    tR([String(i+1),it.item.slice(0,28),it.is_long?'LONG':'BOX',it.sqm.toFixed(1),ap+'%',String(it.bundles)],
      parseFloat(ap)>=5?'#fee2e2':(parseFloat(ap)>=2?'#fef3c7':null));
  });
  gap();

  sec('TOP MATERIALS BY STACKED FOOTPRINT');
  tH(['#','Material','Size (L×W×H)','Stk','FP m²','Bdl']);
  [...items].map(it=>{const{dW,dH}=getDD(it);return{...it,fpA:dW*dH};}).sort((a,b)=>b.fpA-a.fpA).slice(0,15).forEach((it,i)=>{
    tR([String(i+1),it.item.slice(0,24),it.L+'×'+it.W+'×'+it.H+'m',String(it.stack),it.fpA.toFixed(0),String(it.bundles)]);
  });
  gap();

  sec('STORAGE LAYOUT ('+curStrat.toUpperCase()+')');
  kv('Overall area', totalW.toFixed(1)+' × '+totalH.toFixed(1)+' m ('+rentArea.toFixed(0)+' m²)');
  kv('Left / Right zone width', lw.toFixed(1)+' / '+rw.toFixed(1)+' m');
  kv('Corridor', CORR_W+' m wide');
  kv('Material utilization', utilPct+'% of rental area');
  bar('Utilization',parseFloat(utilPct),'#2563eb');
  const leftLanes=(layout&&layout.leftLanes||[]).filter(l=>l.isRow);
  const rightLanes=(layout&&layout.rightLanes||[]).filter(l=>l.isRow);
  kv('Zones (L / R)', leftLanes.length+' / '+rightLanes.length);
  gap();

  sec('CONSTRAINTS & PARAMETERS');
  kv('Corridor width', CORR_W+' m');
  kv('Zone width limit (L/R)', maxZoneWL+' / '+maxZoneWR+' m');
  kv('Forklift', FORK_CAP+'T, max lift '+FORK_MAX_H+'m');
  kv('Trailer deck', DECK_L+'×'+DECK_W+'m, max 2.6m');
  kv('Working hours', WORK_START+':00–'+WORK_END+':00 ('+workMins+' min net)');
  gap();

  sec('TRUCK MOBILIZATION & LOGISTICS');
  kv('Total truck trips', nTrips);
  kv('Avg deck utilization', avgUtil+'%');
  kv('Round trip / Trips per day', roundTrip+'min / '+tripsPerDay);
  kv('Days needed', daysNeeded+' working days',daysNeeded>3?'#fee2e2':null);
  for(let d=1;d<=Math.min(daysNeeded,5);d++){
    const from=(d-1)*tripsPerDay+1, to=Math.min(d*tripsPerDay,nTrips);
    kv('  Day '+d, (to-from+1)+' trips ('+from+'–'+to+')');
  }
  if(daysNeeded>5) note('... '+(daysNeeded-5)+' more days');
  gap();

  sec('ZONE DETAIL');
  const allLanes=[...leftLanes.map(l=>({...l,side:'L'})),...rightLanes.map(l=>({...l,side:'R'}))];
  if(allLanes.length>0){
    tH(['Zone','Side','Material','Area','Bdl','H']);
    allLanes.forEach((lane,li)=>{
      const zi=items.filter(it=>(it.item||it.id)===lane.code);
      const zB=zi.reduce((s,it)=>s+it.bundles,0);
      const zA=zi.reduce((s,it)=>{const{dW,dH}=getDD(it);return s+dW*dH;},0);
      tR(['Z'+(li+1),lane.side,lane.code.slice(0,20),zA.toFixed(0)+'m²',String(zB),lane.height.toFixed(1)+'m']);
    });
  } else { note('No zone data (run layout first)'); }
  gap();

  note('Generated: '+new Date().toLocaleString()+' · Strategy: '+curStrat+' · Scope: '+sc);

  // Compute heights
  const LH=20,SH=28,GH=8,NH=16,TH=22,TR=18,BH=22;
  let ch=50;
  for(const l of L){
    if(l.t==='s')ch+=SH; else if(l.t==='g')ch+=GH; else if(l.t==='n')ch+=NH;
    else if(l.t==='th')ch+=TH; else if(l.t==='tr')ch+=TR; else if(l.t==='b')ch+=BH;
    else ch+=LH;
  }
  _rptLines=L; _rptContentH=ch; _rptDirty=false;
}

function drawReport(){
  const W=cvsW, H=cvsH;
  ctx.clearRect(0,0,W,H);
  ctx.fillStyle='#f8fafc';ctx.fillRect(0,0,W,H);
  if(!items.length) return;

  // Build lines from cache (only recalculates when dirty)
  buildReportLines();
  const lines=_rptLines;
  if(!lines||!lines.length) return;

  const LH=20,SH=28,GH=8,NH=16,TH=22,TR=18,BH=22;
  const totalContentH=_rptContentH;
  const maxScroll=Math.max(0, totalContentH-H+60);
  rptScrollY=Math.max(0, Math.min(rptScrollY, maxScroll));

  ctx.font='bold 16px Segoe UI';ctx.fillStyle='#1e293b';
  ctx.textAlign='center';ctx.textBaseline='top';
  ctx.fillText('OMEGA Full Analysis Report',W/2,8);
  ctx.font='11px Segoe UI';ctx.fillStyle='#64748b';
  ctx.fillText('Area/Volume · GB/T Separated · Logistics',W/2,28);

  const startY=46;
  ctx.save();
  ctx.beginPath();ctx.rect(0,startY,W,H-startY-10);ctx.clip();

  let cy=startY-rptScrollY;
  const mx=20, cw=W-mx*2;

  for(let li=0;li<lines.length;li++){
    const l=lines[li];
    // Skip off-screen lines (fast)
    const lh=l.t==='s'?SH:l.t==='g'?GH:l.t==='n'?NH:l.t==='th'?TH:l.t==='tr'?TR:l.t==='b'?BH:LH;
    if(cy+lh<startY-5){cy+=lh;continue;}
    if(cy>H+5){break;}  // below viewport — stop early

    if(l.t==='s'){
      ctx.fillStyle=l.color||'#1e3a5f';
      ctx.fillRect(mx,cy+2,cw,SH-2);
      ctx.font='bold 11px Segoe UI';ctx.fillStyle='#fff';
      ctx.textAlign='left';ctx.textBaseline='middle';
      ctx.fillText(l.text,mx+8,cy+SH/2+1);
      cy+=SH;
    } else if(l.t==='k'){
      if(l.hl){ctx.fillStyle=l.hl;ctx.fillRect(mx,cy,cw,LH);}
      else if(li%2===0){ctx.fillStyle='#f1f5f9';ctx.fillRect(mx,cy,cw,LH);}
      ctx.font='600 10px Segoe UI';ctx.fillStyle='#475569';
      ctx.textAlign='left';ctx.textBaseline='middle';
      ctx.fillText(l.key,mx+8,cy+LH/2);
      ctx.font='bold 10px Segoe UI';ctx.fillStyle='#0f172a';
      ctx.textAlign='right';
      ctx.fillText(String(l.val),mx+cw-8,cy+LH/2);
      cy+=LH;
    } else if(l.t==='b'){
      const bW=cw-160,bX=mx+130;
      ctx.fillStyle='#e2e8f0';ctx.fillRect(bX,cy+5,bW,BH-10);
      ctx.fillStyle=l.color;ctx.fillRect(bX,cy+5,bW*Math.min(l.pct,100)/100,BH-10);
      ctx.font='600 9px Segoe UI';ctx.fillStyle='#475569';
      ctx.textAlign='left';ctx.textBaseline='middle';
      ctx.fillText(l.label,mx+8,cy+BH/2);
      ctx.font='bold 10px Segoe UI';ctx.fillStyle='#0f172a';
      ctx.textAlign='right';
      ctx.fillText(l.pct.toFixed(1)+'%',mx+cw-8,cy+BH/2);
      cy+=BH;
    } else if(l.t==='th'){
      ctx.fillStyle='#334155';ctx.fillRect(mx,cy,cw,TH);
      const cols=l.cols, cWid=cw/cols.length;
      ctx.font='bold 9px Segoe UI';ctx.fillStyle='#fff';ctx.textBaseline='middle';
      cols.forEach((c,i)=>{
        ctx.textAlign=i===0?'center':(i===1?'left':'center');
        ctx.fillText(c,mx+i*cWid+(i===0?cWid/2:(i===1?6:cWid/2)),cy+TH/2);
      });
      cy+=TH;
    } else if(l.t==='tr'){
      if(l.hl){ctx.fillStyle=l.hl;ctx.fillRect(mx,cy,cw,TR);}
      else if(li%2===0){ctx.fillStyle='#f8fafc';ctx.fillRect(mx,cy,cw,TR);}
      ctx.strokeStyle='#e2e8f0';ctx.lineWidth=0.5;ctx.strokeRect(mx,cy,cw,TR);
      const cols=l.cols, cWid=cw/cols.length;
      ctx.textBaseline='middle';
      cols.forEach((c,i)=>{
        ctx.font=i<=1?'bold 9px Segoe UI':'9px Segoe UI';
        ctx.fillStyle=i>=3?'#475569':'#1e293b';
        ctx.textAlign=i===0?'center':(i===1?'left':'right');
        ctx.fillText(c,mx+i*cWid+(i===0?cWid/2:(i===1?6:cWid-6)),cy+TR/2);
      });
      cy+=TR;
    } else if(l.t==='g'){
      cy+=GH;
    } else if(l.t==='n'){
      ctx.font='italic 9px Segoe UI';ctx.fillStyle='#94a3b8';
      ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.fillText(l.text,W/2,cy+NH/2);
      cy+=NH;
    }
  }
  ctx.restore();

  if(maxScroll>0){
    const sbX=W-10,sbY=startY,sbH=H-startY-10;
    ctx.fillStyle='rgba(0,0,0,0.06)';ctx.fillRect(sbX,sbY,6,sbH);
    const thumbH=Math.max(20,sbH*((H-60)/totalContentH));
    const thumbY=sbY+(rptScrollY/maxScroll)*(sbH-thumbH);
    ctx.fillStyle='rgba(30,58,95,0.35)';ctx.fillRect(sbX,thumbY,6,thumbH);
  }
}

// ══════════════════════ TRUCK LOADING SIMULATOR ══════════════════════
const N_FORKLIFTS=2;
const N_TRAILERS=1;
const WORK_START=8, WORK_END=17; // 8am-5pm
const LUNCH_MIN=60; // 12:00-13:00 lunch break
const BUFFER_MIN=30; // daily buffer (safety check, briefing, delays)
const DRIVE_TIME_MIN=30; // site to warehouse one way
const LOAD_TIME_MIN=15;  // avg time to load one truck
const UNLOAD_TIME_MIN=20; // avg time to unload at warehouse

function planTruckTrips(){
  if(!items.length) return [];
  const allBundles=[];
  for(const it of items){
    const effStack=Math.min(it.stack, Math.max(1,Math.floor(DECK_MAX_H/it.H)));
    const loads=Math.ceil(it.bundles/effStack);
    for(let i=0;i<loads;i++){
      const bdlCount=Math.min(effStack, it.bundles-i*effStack);
      allBundles.push({
        item:it.item, L:it.L, W:it.W, H:it.H*bdlCount,
        is_long:it.is_long, bdlCount, srcId:it.id, area:it.L*it.W
      });
    }
  }
  allBundles.sort((a,b)=>(b.L*b.W)-(a.L*a.W));

  const trips=[];
  for(const bdl of allBundles){
    let placed=false;
    for(const trip of trips){
      if(tryPlaceOnDeck(trip, bdl)){placed=true;break;}
    }
    if(!placed){
      const trip={loads:[], usedCells:[]};
      tryPlaceOnDeck(trip, bdl);
      trips.push(trip);
    }
  }
  return trips;
}

function tryPlaceOnDeck(trip, bdl){
  // Edge-candidate placement: try (0,0) + right/bottom edges of existing loads
  for(const rot of [false, true]){
    const bL=rot?bdl.W:bdl.L;
    const bW=rot?bdl.L:bdl.W;
    if(bL>DECK_L || bW>DECK_W) continue;

    // Build candidate positions from edges of placed loads + origin
    const cands=[[0,0]];
    for(const ld of trip.loads){
      cands.push([ld.x+ld.w, ld.y]);  // right edge
      cands.push([ld.x, ld.y+ld.h]);  // bottom edge
      cands.push([ld.x+ld.w, ld.y+ld.h]); // corner
    }
    for(const[tx,ty] of cands){
      if(tx<-0.001||ty<-0.001||tx+bL>DECK_L+0.001||ty+bW>DECK_W+0.001) continue;
      let fits=true;
      for(const ld of trip.loads){
        if(tx<ld.x+ld.w-0.001 && tx+bL>ld.x+0.001 && ty<ld.y+ld.h-0.001 && ty+bW>ld.y+0.001){
          fits=false;break;
        }
      }
      if(fits){
        trip.loads.push({x:tx, y:ty, w:bL, h:bW, sH:bdl.H, item:bdl.item, is_long:bdl.is_long, bdlCount:bdl.bdlCount, rot});
        return true;
      }
    }
  }
  return false;
}

function calcLogistics(nTrips){
  const roundTripMin=LOAD_TIME_MIN+DRIVE_TIME_MIN+UNLOAD_TIME_MIN+DRIVE_TIME_MIN;
  const grossMin=(WORK_END-WORK_START)*60; // 540 min
  const netMin=grossMin-LUNCH_MIN-BUFFER_MIN; // 450 min (deduct lunch + buffer)
  const workMinPerDay=netMin;
  const tripsPerTrailerPerDay=Math.floor(workMinPerDay/roundTripMin);
  const tripsPerDay=tripsPerTrailerPerDay*N_TRAILERS;
  const daysNeeded=Math.ceil(nTrips/tripsPerDay);
  return{roundTripMin,grossMin,workMinPerDay,tripsPerTrailerPerDay,tripsPerDay,daysNeeded};
}

function drawTruckLoad(){
  const W=cvsW, H=cvsH;
  ctx.clearRect(0,0,W,H);
  ctx.fillStyle='#f1f5f9';ctx.fillRect(0,0,W,H);
  _tlClickZones=[];
  if(!items.length) return;

  const trips=getCachedTruckTrips();
  const nTrips=trips.length;
  const totalBdl=items.reduce((s,it)=>s+it.bundles,0);
  const log=calcLogistics(nTrips);

  // Truck grid metrics
  const maxPerRow=Math.min(3, nTrips);
  const truckViewW=Math.min(320, (W-60)/maxPerRow-15);
  const scale=truckViewW/DECK_L;
  const truckViewH=DECK_W*scale;
  const cellH=truckViewH+90;

  // Calculate total content height needed for scrolling
  const nRows=Math.ceil(nTrips/maxPerRow);
  const totalContentH=48+nRows*cellH+90;

  // Title
  ctx.font='bold 15px Segoe UI';ctx.fillStyle='#1e293b';
  ctx.textAlign='center';ctx.textBaseline='top';
  ctx.fillText(`Truck Loading Plan — 12m Flatbed (${DECK_L}×${DECK_W}m)`,W/2,8-tlScrollY);
  ctx.font='11px Segoe UI';ctx.fillStyle='#64748b';
  ctx.fillText(`${nTrips} trips · ${totalBdl} bundles · ${log.daysNeeded} working day${log.daysNeeded>1?'s':''} (${N_FORKLIFTS} forklifts, ${N_TRAILERS} trailer, 8am-5pm)`,W/2,26-tlScrollY);

  for(let t=0;t<nTrips;t++){
    const trip=trips[t];
    const col=t%maxPerRow;
    const row=Math.floor(t/maxPerRow);
    const ox=20+col*(truckViewW+40);
    const oy=48+row*cellH-tlScrollY;

    // Trip header
    const usedArea=trip.loads.reduce((s,ld)=>s+ld.w*ld.h,0);
    const deckArea=DECK_L*DECK_W;
    const util=(usedArea/deckArea*100);
    ctx.font='bold 10px Segoe UI';ctx.fillStyle='#1e293b';
    ctx.textAlign='left';ctx.textBaseline='top';
    ctx.fillText(`Trip ${t+1}`,ox,oy);
    ctx.font='9px Segoe UI';ctx.fillStyle='#64748b';
    ctx.fillText(`${trip.loads.length} pcs · ${util.toFixed(0)}% · ${usedArea.toFixed(1)}m²`,ox+45,oy+1);

    const dy=oy+14;

    // Deck background + grid
    ctx.fillStyle='#e8ecf1';
    ctx.fillRect(ox,dy,truckViewW,truckViewH);
    // 1m grid
    ctx.strokeStyle='rgba(148,163,184,0.3)';ctx.lineWidth=0.5;
    for(let gx=0;gx<=DECK_L;gx++){
      const px=ox+gx*scale;
      ctx.beginPath();ctx.moveTo(px,dy);ctx.lineTo(px,dy+truckViewH);ctx.stroke();
    }
    ctx.strokeStyle='#475569';ctx.lineWidth=1.5;
    ctx.strokeRect(ox,dy,truckViewW,truckViewH);

    // Cab
    ctx.fillStyle='#6b7280';
    const cabW=14;
    ctx.fillRect(ox+truckViewW+1,dy+2,cabW,truckViewH-4);
    ctx.strokeStyle='#374151';ctx.lineWidth=1;
    ctx.strokeRect(ox+truckViewW+1,dy+2,cabW,truckViewH-4);
    ctx.fillStyle='#d1d5db';
    ctx.fillRect(ox+truckViewW+3,dy+truckViewH*0.3,cabW-4,truckViewH*0.4);

    // Wheels
    ctx.fillStyle='#1f2937';
    [[ox-3,dy+4],[ox-3,dy+truckViewH-8],[ox+truckViewW+cabW+1,dy+4],[ox+truckViewW+cabW+1,dy+truckViewH-8]].forEach(([wx,wy])=>{
      ctx.fillRect(wx,wy,4,8);
    });
    // Rear axle wheels
    [[ox-3,dy+truckViewH-20],[ox+truckViewW+cabW+1,dy+truckViewH-20]].forEach(([wx,wy])=>{
      ctx.fillRect(wx,wy,4,8);
    });

    // Draw loaded items (no overlap guaranteed)
    for(const ld of trip.loads){
      const ix=ox+ld.x*scale;
      const iy=dy+ld.y*scale;
      const iw=ld.w*scale;
      const ih=ld.h*scale;

      // Record click zone
      _tlClickZones.push({x:ix,y:iy,w:iw,h:ih,item:ld.item});

      // Check if this item is selected
      const isSel=selId&&items.find(i=>i.id===selId&&i.item===ld.item);

      ctx.fillStyle=isSel?'rgba(234,179,8,0.9)':(ld.is_long?'rgba(59,130,246,0.8)':'rgba(34,197,94,0.8)');
      ctx.fillRect(ix+0.5,iy+0.5,iw-1,ih-1);
      ctx.strokeStyle=isSel?'#b45309':(ld.is_long?'#1e40af':'#166534');
      ctx.lineWidth=isSel?2:1;
      ctx.strokeRect(ix+0.5,iy+0.5,iw-1,ih-1);

      if(iw>30 && ih>12){
        const fs=Math.min(9, iw*0.13, ih*0.5);
        ctx.font=`600 ${fs}px Segoe UI`;
        ctx.fillStyle=isSel?'#1e293b':'#fff';ctx.textAlign='center';ctx.textBaseline='middle';
        const maxChars=Math.max(3,Math.floor(iw/(fs*0.55)));
        const name=ld.item.length>maxChars?ld.item.slice(0,maxChars-1)+'…':ld.item;
        ctx.fillText(name,ix+iw/2,iy+ih/2);
      }
    }

    // Detail list under truck
    const dlY=dy+truckViewH+3;
    ctx.font='8px Segoe UI';ctx.fillStyle='#475569';ctx.textAlign='left';ctx.textBaseline='top';
    const uniqueItems={};
    for(const ld of trip.loads){
      if(!uniqueItems[ld.item]) uniqueItems[ld.item]={count:0,is_long:ld.is_long};
      uniqueItems[ld.item].count+=ld.bdlCount;
    }
    let detailTxt=Object.entries(uniqueItems).map(([name,v])=>`${name.slice(0,15)}×${v.count}`).join(' · ');
    if(detailTxt.length>truckViewW/4.5) detailTxt=detailTxt.slice(0,Math.floor(truckViewW/4.5))+'…';
    ctx.fillText(detailTxt,ox,dlY);

    // Utilisation bar
    const barY=dlY+11;
    ctx.fillStyle='#e2e8f0';ctx.fillRect(ox,barY,truckViewW,6);
    ctx.fillStyle=util>80?'#16a34a':util>50?'#eab308':'#ef4444';
    ctx.fillRect(ox,barY,truckViewW*(util/100),6);
    ctx.strokeStyle='#94a3b8';ctx.lineWidth=0.5;
    ctx.strokeRect(ox,barY,truckViewW,6);
  }

  // ── LOGISTICS SUMMARY BOX ── (now flows below trucks instead of fixed at bottom)
  const boxY=48+nRows*cellH+10-tlScrollY;
  ctx.fillStyle='#1e3a5f';ctx.fillRect(10,boxY,W-20,72);
  ctx.strokeStyle='#0f172a';ctx.lineWidth=1;ctx.strokeRect(10,boxY,W-20,72);

  ctx.font='bold 12px Segoe UI';ctx.fillStyle='#fff';
  ctx.textAlign='left';ctx.textBaseline='top';
  ctx.fillText('MOBILIZATION & LOGISTICS ANALYSIS',20,boxY+6);

  ctx.font='10px Segoe UI';ctx.fillStyle='#93c5fd';
  const avgUtil=trips.length?trips.reduce((s,t)=>s+t.loads.reduce((s2,l)=>s2+l.w*l.h,0)/(DECK_L*DECK_W)*100,0)/trips.length:0;

  const col1=20, col2=W*0.35, col3=W*0.68;
  ctx.fillText(`Truck trips: ${nTrips}`,col1,boxY+24);
  ctx.fillText(`Avg utilisation: ${avgUtil.toFixed(0)}%`,col1,boxY+38);
  ctx.fillText(`Total bundles: ${totalBdl}`,col1,boxY+52);

  ctx.fillText(`Round trip: ${log.roundTripMin} min (load ${LOAD_TIME_MIN}′ + drive ${DRIVE_TIME_MIN}′ + unload ${UNLOAD_TIME_MIN}′ + return ${DRIVE_TIME_MIN}′)`,col2,boxY+24);
  ctx.fillText(`Trips/day: ${log.tripsPerDay} (${log.workMinPerDay} min ÷ ${log.roundTripMin} min/trip)`,col2,boxY+38);
  ctx.fillText(`Working: ${WORK_START}:00–${WORK_END}:00 (${log.workMinPerDay} min, lunch 12–1pm)`,col2,boxY+52);

  ctx.fillStyle='#fbbf24';ctx.font='bold 11px Segoe UI';
  ctx.fillText(`⏱ ${log.daysNeeded} working day${log.daysNeeded>1?'s':''} to complete`,col3,boxY+24);
  ctx.fillStyle='#93c5fd';ctx.font='10px Segoe UI';
  ctx.fillText(`${N_FORKLIFTS} forklifts · ${N_TRAILERS} trailer`,col3,boxY+38);
  ctx.fillText(`Drive: ${DRIVE_TIME_MIN} min one-way (site → warehouse)`,col3,boxY+52);
}

// ══════════════════════ INIT ══════════════════════
buildSelects();
document.getElementById('shipSel').value='0';
updateLegend();
onShip();
